//  XPVehicleSDK
//
//  Created by YuanGuo on 2025/5/22.
//

import Foundation

@objcMembers
public class CarKeyAutoLockRequestParam: NSObject, Codable {
    let keyIds: [String]
    let pe: Bool
    let pollingLock: Bool
    let pollingUnLock: Bool
    let lockDistance: Double
    let unLockDistance: Double

    /// Designated initializer
    public init(keyIds: [String],
         pe: Bool,
         pollingLock: Bool,
         pollingUnLock: Bool,
         lockDistance: Double,
         unLockDistance: Double) {
        self.keyIds = keyIds
        self.pe = pe
        self.pollingLock = pollingLock
        self.pollingUnLock = pollingUnLock
        self.lockDistance = lockDistance
        self.unLockDistance = unLockDistance
    }

    // MARK: - Codable

    enum CodingKeys: String, CodingKey {
        case keyIds
        case pe
        case pollingLock
        case pollingUnLock
        case lockDistance
        case unLockDistance
    }

    required public init(from decoder: Decoder) throws {
            let container = try decoder.container(keyedBy: CodingKeys.self)
            keyIds = try container.decode([String].self, forKey: .keyIds)
            pe = try container.decode(Bool.self, forKey: .pe)
            pollingLock = try container.decode(Bool.self, forKey: .pollingLock)
            pollingUnLock = try container.decode(Bool.self, forKey: .pollingUnLock)
            lockDistance = try container.decode(Double.self, forKey: .lockDistance)
            unLockDistance = try container.decode(Double.self, forKey: .unLockDistance)
        }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(keyIds, forKey: .keyIds)
        try container.encode(pe, forKey: .pe)
        try container.encode(pollingLock, forKey: .pollingLock)
        try container.encode(pollingUnLock, forKey: .pollingUnLock)
        try container.encode(lockDistance, forKey: .lockDistance)
        try container.encode(unLockDistance, forKey: .unLockDistance)
    }

    // MARK: - Utility Methods

    /// Converts the configuration to a dictionary
    public func toDictionary() -> [String: Any] {
        return [
            "keyIds": keyIds,
            "pe": pe,
            "pollingLock": pollingLock,
            "pollingUnLock": pollingUnLock,
            "lockDistance": lockDistance,
            "unLockDistance": unLockDistance
        ]
    }

    /// Creates configuration from dictionary
    static func from(dictionary: [String: Any]) -> CarKeyAutoLockRequestParam? {
        guard let keyIds = dictionary["keyIds"] as? [String],
              let pe = dictionary["pe"] as? Bool,
              let pollingLock = dictionary["pollingLock"] as? Bool,
              let pollingUnLock = dictionary["pollingUnLock"] as? Bool,
              let lockDistance = dictionary["lockDistance"] as? Double,
              let unLockDistance = dictionary["unLockDistance"] as? Double else {
            return nil
        }

        return CarKeyAutoLockRequestParam(
            keyIds: keyIds,
            pe: pe,
            pollingLock: pollingLock,
            pollingUnLock: pollingUnLock,
            lockDistance: lockDistance,
            unLockDistance: unLockDistance
        )
    }

    /// Creates configuration from JSON data
    static func from(jsonData: Data) -> CarKeyAutoLockRequestParam? {
        let decoder = JSONDecoder()
        return try? decoder.decode(CarKeyAutoLockRequestParam.self, from: jsonData)
    }
}

