87	    private func queryServerEndActivedBleKey(vin: String, localBleKey: BleKeyInfo?, completion: @escaping (_ status: Int) -> Void) {
88	        DKLog.log("查询钥匙-本地没有有效已激活且上报蓝牙钥匙，从云端查一次")
89	        // 这里只查云端已激活的钥匙
90	        getActivedBleKey(vin) {[weak self] serverBleKey in
91	            guard let self = self else { return }
92	            // 云端没有钥匙、本地没有钥匙，直接返回无钥匙
93	            if serverBleKey == nil && localBleKey == nil {
94	                DKLog.log("查询钥匙-云端无已激活钥匙，本地无激活钥匙，返回未创建状态")
95	                completion(0)
96	                return
97	            }
98	            
99	            // 云端有钥匙、本地没钥匙，直接用云端钥匙状态
100	            if serverBleKey != nil && localBleKey == nil {
101	                serverBleKey!.syncFlag = true
102	                DKSqlStoreUtil.xp_save(uid: self.uid, vin: vin, dkModel: serverBleKey!) { result in
103	                    BleKeyManager.shared.handleBleKeyDidCreate(bleKey: serverBleKey!)
104	                    DKLog.log("查询钥匙-使用云端已激活钥匙1, dkId: \(serverBleKey!.dkId)")
105	                    completion(1)
106	                    return
107	                }
108	                return
109	            }
110	            
111	            // 云端有钥匙、本地也有钥匙，钥匙信息不一样，直接用云端钥匙覆盖
112	            if serverBleKey != nil && localBleKey != nil {
113	                if localBleKey!.activeStatus == 1, localBleKey!.dkId == serverBleKey!.dkId, localBleKey!.syncFlag == true, serverBleKey == localBleKey {
114	                    DKLog.log("查询钥匙-使用本地已激活钥匙2, dkId: \(localBleKey!.dkId)")
115	                    completion(1)
116	                    return
117	                } else {
118	                    serverBleKey!.syncFlag = true
119	                    DKSqlStoreUtil.xp_save(uid: self.uid, vin: vin, dkModel: serverBleKey!) { result in
120	                        DKLog.log("查询钥匙-使用云端已激活钥匙2, dkId: \(serverBleKey!.dkId)")
121	                        completion(1)
122	                        return
123	                    }
124	                }
125	                return
126	            }
127	            
128	            // 云端没有已激活钥匙、本地有待激活或者已激活未上报的钥匙则使用本地钥匙，其它钥匙状态直接删除本地钥匙，与云端同步
129	            if serverBleKey == nil && localBleKey != nil {
130	                if localBleKey!.activeStatus == 0 {
131	                    DKLog.log("查询钥匙-使用本地待激活钥匙3, dkId: \(localBleKey!.dkId)")
132	                    completion(2)
133	                    return
134	                }
135	                if localBleKey!.activeStatus == 1 && localBleKey!.syncFlag == false {
136	                    DKLog.log("查询钥匙-使用本地已激活钥匙4, dkId: \(localBleKey!.dkId)")
137	                    completion(1)
138	                    return
139	                }
140	                DKSqlStoreUtil.xp_delete(uid: self.uid, vin: vin) { result in
141	                    DKLog.log("查询钥匙-云端无激活钥匙，本地有钥匙且状态为激活失败则删除本地钥匙")
142	                    Self.reportBleKeyActiveState(vin: vin, dkId: localBleKey!.dkId, activeCode: .delete, msg: "查询钥匙时删除", completion: { _ in })
143	                    completion(0)
144	                    return
145	                }
146	            }
147	        }
