168	    func create(onSuccess: MonaCallback<MonaResponse<BleKeyInfo>>? = nil, onError: MonaCallback<MonaError>? = nil) {
169	        DKLog.log("创建钥匙-方法调用")
170	        guard !vin.isEmpty else {
171	            let monaError = MonaError()
172	            monaError.code = MonaErrorCode.noVin.rawValue
173	            monaError.message = MonaErrorCode.noVin.msg
174	            onError?(monaError)
175	            return
176	        }
177	        
178	        DKRequest.post(
179	            path: creatDigitalKeyPath,
180	            parameters: ["vin": vin],
181	            model: BleKeyInfo.self
182	        ) {[weak self] response in
183	            guard let self = self else { return }
184	            self.invalidTimer()
185	            if let bleKeyInfo = response.data {
186	                DKLog.log("创建钥匙-成功，vin:\(self.vin)")
187	                DKSqlStoreUtil.xp_save(uid: self.uid, vin: self.vin, dkModel: bleKeyInfo) { result in
188	                    onSuccess?(response)
189	                    BleKeyManager.shared.handleBleKeyDidCreate(bleKey: bleKeyInfo)
190	                }
191	            } else {
192	                let monaError = MonaError()
193	                monaError.code = MonaErrorCode.jsonParseFail.rawValue
194	                monaError.message = MonaErrorCode.jsonParseFail.msg
195	                onError?(monaError)
196	            }
197	        } onError: {[weak self] response in
198	            self?.invalidTimer()
199	            onError?(response.toMonaError())
200	        }
201	        
202	        // 开启10s倒计时
203	        createTimer = Timer.scheduledTimer(withTimeInterval: createTimeout, repeats: false) {[weak self] timer in
204	            DKLog.log("创建钥匙-失败，10s内未创建成功")
205	            self?.invalidTimer()
206	            let monaError = MonaError()
207	            monaError.code = MonaErrorCode.timeout.rawValue
208	            monaError.message = MonaErrorCode.timeout.msg
209	            onError?(monaError)
210	            return
211	        }
212	    }
