360	    private func reportUserUnlockSettings(params: [String: Any], onSuccess: @escaping BleKeyConfigCallback, onError: @escaping MonaErrorCallback) {
361	        var settingParams: [String: Any] = ["phoneModel": DeviceInfo.model, "vin": vin]
362	        settingParams.merge(params, uniquingKeysWith: { $1 })
363	        DKRequest.post(
364	            path: setUnlockSettingUrl,
365	            parameters: settingParams,
366	            model: BleKeyConfigModel.self) {[weak self] response in
367	                guard let self = self else { return }
368	                let resp = BleKeyConfigResponse()
369	                resp.code = response.code
370	                resp.message = response.message
371	                resp.data = response.data
372	                resp.traceId = response.traceId
373	                onSuccess(resp)
374	                if let model = response.data {
375	                    SQLManager.shared.insertUserSetting(uid:"\(self.uid)", vin: self.vin, model: model, completion: nil)
376	                }
377	                if response.data != nil && params.keys.contains { ["lockSettings", "enableSettings"].contains($0) } {
378	                    self.notifyPollingConfigDidChange(response.data!)
379	                }
380	            } onError: { response in
381	                response.message = "设置失败，请重试"
382	                onError(response.toMonaError())
383	            }
