386	    func checkUserSettings(
387	        vin: String?,
388	        onSuccess: ((_ response: MonaResponse<[BleKeyConfigModel]>)-> Void)?,
389	        onError:  MonaErrorCallback?) {
390	            var params = ["phoneModel": DeviceInfo.model]
391	            params["vin"] = vin != nil ? vin : ""
392	            DKRequest.post(
393	                path: checkUserSettingUrl,
394	                parameters: params,
395	                model: [BleKeyConfigModel].self) {[weak self] response in
396	                    onSuccess?(response)
397	                    guard let self = self else { return }
398	                    guard let settings = response.data, settings.count > 0 else { return }
399	                    for item in settings {
400	                        if item.vin == nil || item.vin!.isEmpty {
401	                            continue
402	                        }
403	                        SQLManager.shared.insertUserSetting(uid: "\(self.uid)", vin: item.vin!, model: item, completion: nil)
404	                        if item.vin! == self.vin {
405	                            self.updateCurrentBleKeyConfig(item)
406	                            // 发当前车辆Polling设置
407	                            self.notifyPollingConfigDidChange(item)
408	                        }
409	                    }
410	                } onError: { response in
411	                    onError?(response.toMonaError())
412	                }
413	        }
