//
//  BleKeyHandler.swift
//  CarServiceSDK
//
//  Created by didi on 2024/1/23.
//

import Foundation
import MMKV

enum BleKeyActiveCode: Int {
    case success = 1
    case failure = 2
    case delete = 3
}

/// 钥匙管理及设置
class BleKeyHandler {
    static let enableLockSettingsKey: String = "monasdkenableLockSettingsKey"

    private let uid: UInt64
    private let vin: String

    private var createTimer: Timer?
    private let createTimeout: TimeInterval = 10

    init(uid: UInt64, vin: String) {
        self.uid = uid
        self.vin = vin
    }

    static func reportBleKeyActiveState(vin: String, dkId: String, activeCode: BleKeyActiveCode, msg: String? = nil, completion: @escaping (_ result: Bool) -> Void) {
        var params = [
            "dkid": dkId,
            "activeCode": "\(activeCode.rawValue)",
            "vin": vin
        ]
        if let msg = msg, msg.count > 0 {
            params["msg"] = msg
        }
        DKRequest.post(
            path: reportBleKeyActiveStatePath,
            parameters: params,
            model: String.self) { response in
                completion(true)
            } onError: { error in
                completion(false)
            }
    }

    func getCALData(_ onSuccess: @escaping CarControlCallback, onError: MonaErrorCallback? = nil) {
//        CarServiceManager.queryLatestCalibrationData { result in
//            guard let result = result else {
//                let monaError = MonaError()
//                monaError.code = -1
//                onError?(monaError)
//                return
//            }
//            let resp = CarControlResponse()
//            resp.code = 0
//            resp.data = result
//            onSuccess(resp)
//        }
    }

    func hasBleKey(vin: String, onSuccess: @escaping (_ state: Int) -> Void) {
        DKLog.log("查询钥匙-业务调用, vin：\(vin)")
        DKSqlStoreUtil.xp_get(uid: uid, vin: vin) {[weak self] bleKeyInfo in
            guard let self = self else { return }

            if bleKeyInfo != nil, bleKeyInfo!.activeStatus == 1, bleKeyInfo!.syncFlag == true {
                self.checkBleKeyValid(bleKey: bleKeyInfo!) { result in
                    if result {
                        DKLog.log("查询钥匙-使用本地已激活钥匙1, dkId: \(bleKeyInfo!.dkId)")
                        onSuccess(1)
                        return
                    } else {
                        self.queryServerEndActivedBleKey(vin: vin, localBleKey: bleKeyInfo, completion: onSuccess)
                    }
                }
            } else {
                self.queryServerEndActivedBleKey(vin: vin, localBleKey: bleKeyInfo, completion: onSuccess)
            }
        }
    }

    private func queryServerEndActivedBleKey(vin: String, localBleKey: BleKeyInfo?, completion: @escaping (_ status: Int) -> Void) {
        DKLog.log("查询钥匙-本地没有有效已激活且上报蓝牙钥匙，从云端查一次")
        // 这里只查云端已激活的钥匙
        getActivedBleKey(vin) {[weak self] serverBleKey in
            guard let self = self else { return }
            // 云端没有钥匙、本地没有钥匙，直接返回无钥匙
            if serverBleKey == nil && localBleKey == nil {
                DKLog.log("查询钥匙-云端无已激活钥匙，本地无激活钥匙，返回未创建状态")
                completion(0)
                return
            }

            // 云端有钥匙、本地没钥匙，直接用云端钥匙状态
            if serverBleKey != nil && localBleKey == nil {
                serverBleKey!.syncFlag = true
                DKSqlStoreUtil.xp_save(uid: self.uid, vin: vin, dkModel: serverBleKey!) { result in
                    BleKeyManager.shared.handleBleKeyDidCreate(bleKey: serverBleKey!)
                    DKLog.log("查询钥匙-使用云端已激活钥匙1, dkId: \(serverBleKey!.dkId)")
                    completion(1)
                    return
                }
                return
            }

            // 云端有钥匙、本地也有钥匙，钥匙信息不一样，直接用云端钥匙覆盖
            if serverBleKey != nil && localBleKey != nil {
                if localBleKey!.activeStatus == 1, localBleKey!.dkId == serverBleKey!.dkId, localBleKey!.syncFlag == true, serverBleKey == localBleKey {
                    DKLog.log("查询钥匙-使用本地已激活钥匙2, dkId: \(localBleKey!.dkId)")
                    completion(1)
                    return
                } else {
                    serverBleKey!.syncFlag = true
                    DKSqlStoreUtil.xp_save(uid: self.uid, vin: vin, dkModel: serverBleKey!) { result in
                        DKLog.log("查询钥匙-使用云端已激活钥匙2, dkId: \(serverBleKey!.dkId)")
                        completion(1)
                        return
                    }
                }
                return
            }

            // 云端没有已激活钥匙、本地有待激活或者已激活未上报的钥匙则使用本地钥匙，其它钥匙状态直接删除本地钥匙，与云端同步
            if serverBleKey == nil && localBleKey != nil {
                if localBleKey!.activeStatus == 0 {
                    DKLog.log("查询钥匙-使用本地待激活钥匙3, dkId: \(localBleKey!.dkId)")
                    completion(2)
                    return
                }
                if localBleKey!.activeStatus == 1 && localBleKey!.syncFlag == false {
                    DKLog.log("查询钥匙-使用本地已激活钥匙4, dkId: \(localBleKey!.dkId)")
                    completion(1)
                    return
                }
                DKSqlStoreUtil.xp_delete(uid: self.uid, vin: vin) { result in
                    DKLog.log("查询钥匙-云端无激活钥匙，本地有钥匙且状态为激活失败则删除本地钥匙")
                    Self.reportBleKeyActiveState(vin: vin, dkId: localBleKey!.dkId, activeCode: .delete, msg: "查询钥匙时删除", completion: { _ in })
                    completion(0)
                    return
                }
            }
        }
    }


    private func checkBleKeyValid(bleKey: BleKeyInfo, completion: @escaping (_ result: Bool) -> Void) {
        let dkList: [[String: Any]] = [[
            "dkId": bleKey.dkId,
            "updateTime": bleKey.updateTime ?? ""
        ]]
        DKRequest.post(
            path: getLatestDigitalKeyPath,
            parameters: ["btChainList": dkList],
            model: [BleKeyInfo].self) { response in
                let isValid = response.data?.first?.status == 0
                completion(isValid)
            } onError: { response in
                completion(true)
            }
    }


    func create(onSuccess: MonaCallback<MonaResponse<BleKeyInfo>>? = nil, onError: MonaCallback<MonaError>? = nil) {
        DKLog.log("创建钥匙-方法调用")
        guard !vin.isEmpty else {
            let monaError = MonaError()
            monaError.code = MonaErrorCode.noVin.rawValue
            monaError.message = MonaErrorCode.noVin.msg
            onError?(monaError)
            return
        }

        DKRequest.post(
            path: creatDigitalKeyPath,
            parameters: ["vin": vin],
            model: BleKeyInfo.self
        ) {[weak self] response in
            guard let self = self else { return }
            self.invalidTimer()
            if let bleKeyInfo = response.data {
                DKLog.log("创建钥匙-成功，vin:\(self.vin)")
                DKSqlStoreUtil.xp_save(uid: self.uid, vin: self.vin, dkModel: bleKeyInfo) { result in
                    onSuccess?(response)
                    BleKeyManager.shared.handleBleKeyDidCreate(bleKey: bleKeyInfo)
                }
            } else {
                let monaError = MonaError()
                monaError.code = MonaErrorCode.jsonParseFail.rawValue
                monaError.message = MonaErrorCode.jsonParseFail.msg
                onError?(monaError)
            }
        } onError: {[weak self] response in
            self?.invalidTimer()
            onError?(response.toMonaError())
        }

        // 开启10s倒计时
        createTimer = Timer.scheduledTimer(withTimeInterval: createTimeout, repeats: false) {[weak self] timer in
            DKLog.log("创建钥匙-失败，10s内未创建成功")
            self?.invalidTimer()
            let monaError = MonaError()
            monaError.code = MonaErrorCode.timeout.rawValue
            monaError.message = MonaErrorCode.timeout.msg
            onError?(monaError)
            return
        }
    }

    func getBleKeyInfo(vin: String, onSuccess: @escaping (_ bleKeyInfo: BleKeyInfo?) -> Void) {
        DKLog.log("调用获取本地钥匙信息方法")
        DKSqlStoreUtil.xp_get(uid: uid, vin: vin) {
            onSuccess($0)
        }
    }

    func getActivedBleKey(_ vin: String, completion: @escaping (_ bleKeyInfo: BleKeyInfo?) -> Void) {
        DKRequest.post(
            path: getKeyPath,
            parameters: ["vin": vin],
            model: BleKeyInfo.self) { response in
                completion(response.data)
            } onError: { response in
                completion(nil)
            }
    }

    func deleteBleKey(vin: String, needReport: Bool = true, onSuccess: @escaping (_ result: Bool) -> Void) {
        DKLog.log("删除钥匙-调用删除钥匙方法")
        DKSqlStoreUtil.xp_get(uid: uid, vin: vin) { bleKeyInfo in
            guard let bleKeyInfo = bleKeyInfo else {
                DKLog.log("删除钥匙-失败，本地没有蓝牙钥匙")
                onSuccess(false)
                return
            }

            let dkId = bleKeyInfo.dkId
            DKRequest.post(
                path: reportBleKeyActiveStatePath,
                parameters: [
                    "dkid": dkId,
                    "activeCode": "3",
                    "vin": vin
                ],
                model: String.self) {[weak self] response in
                    guard let self = self else { return }
                    DKSqlStoreUtil.xp_delete(uid: self.uid, vin: vin) { result in
                        DKLog.log("删除钥匙-\(result ? "成功" : "失败")")
                        onSuccess(result)
                        BleKeyManager.shared.handleBleKeyDidDelete()
                    }
                } onError: { error in
                    DKLog.log("删除钥匙-失败，上报云端删除时发生错误")
                    onSuccess(false)
                }
        }
    }

    private func invalidTimer() {
        if createTimer != nil, createTimer!.isValid {
            createTimer?.invalidate()
            createTimer = nil
        }
    }

    // MARK: - 解除用车授权

    func removeVehicleAuthorization(vin: String) {
        DKLog.log("钥匙管理，解除用户授权")
        // 删除钥匙
        DKSqlStoreUtil.xp_delete(uid: uid, vin: vin) { result in
            BleKeyManager.shared.handleBleKeyDidDelete()
            // 如果当前蓝牙正连接上，断开蓝牙
            NotificationCenter.default.post(name: .disconnectBle, object: nil, userInfo: [
                "vin": vin,
                "isExternal": true
            ])
        }
        // 删除用户设置
        SQLManager.shared.deleteUserSetting(uid: "\(uid)", vin: vin)
        // 移除外设缓存
        NotificationCenter.default.post(name: .deletePeripheralCache, object: nil, userInfo: ["vin": vin])
    }

    //MARK: - 钥匙解锁设置相关

    /// 一键开启自动解闭锁
    /// - Parameters:
    ///   - onSuccess: 成功回调
    ///   - onError: 失败回调
    func enableAutoLockUnlock(_ onSuccess: @escaping BleKeyConfigCallback, onError: @escaping MonaErrorCallback) {
        DKLog.log("一键开启自动解闭锁")
        let params = [
            "enableSettings": true,
            "lockSettings": true
        ]
        reportUserUnlockSettings(params: params, onSuccess: onSuccess, onError: onError)
    }

    func setProximityAutoUnlock(enabled: Bool, onSuccess: @escaping BleKeyConfigCallback, onError: @escaping MonaErrorCallback) {
        let params = ["enableSettings": enabled]
        DKLog.log("设置是否自动解锁：\(enabled)")
        reportUserUnlockSettings(params: params, onSuccess: onSuccess, onError: onError)
    }

    /// 设置解锁距离
    /// - Parameters:
    ///   - distance: 解锁距离档位 0-默认 1-远 2-近
    ///   - onSuccess: 成功回调
    ///   - onError: 失败回调
    func setUnlockDistance(distance: Int, onSuccess: @escaping CarControlCallback, onError: @escaping MonaErrorCallback) {
        let params = ["unlockDistance": distance]
        DKLog.log("设置解锁距离：\(distance), 0-默认 1-远 2-近")
        let successCallback: BleKeyConfigCallback = { response in
            let resp = CarControlResponse()
            resp.code = response.code
            resp.message = response.message
            resp.traceId = response.traceId
            onSuccess(resp)
        }
        reportUserUnlockSettings(params: params, onSuccess: successCallback, onError: onError)
    }

    func setAutoLockSwitch(enabled: Bool, onSuccess: @escaping BleKeyConfigCallback, onError: @escaping MonaErrorCallback) {
        DKLog.log("设置自动闭锁：\(enabled)")
        let params = ["lockSettings": enabled]
        reportUserUnlockSettings(params: params, onSuccess: onSuccess, onError: onError)
    }

    func setUnlockType(type: Int, onSuccess: @escaping BleKeyConfigCallback, onError: @escaping MonaErrorCallback) {
        DKLog.log("设置解锁方式：\(type)")
        let params = ["unlockType": type]
        reportUserUnlockSettings(params: params, onSuccess: onSuccess, onError: onError)
    }

    /// 获取用户解锁设置
    /// - Parameters:
    ///   - vin: 车辆vin码
    ///   - onSuccess: 成功回调
    ///   - onError: 失败回调
    func getUserUnlockSetting(vin: String, onSuccess: @escaping (_ model: BleKeyConfigModel) -> Void, onError: @escaping MonaErrorCallback) {
        checkUserSettings(vin: vin) { respone in
            if let model = respone.data?.first {
                onSuccess(model)
            } else {
                let error = MonaError()
                error.code = -1
                error.message = "用户无配置"
                onError(error)
            }
        } onError: { error in
            onError(error)
        }
    }

    private func reportUserUnlockSettings(params: [String: Any], onSuccess: @escaping BleKeyConfigCallback, onError: @escaping MonaErrorCallback) {
        var settingParams: [String: Any] = ["phoneModel": DeviceInfo.model, "vin": vin]
        settingParams.merge(params, uniquingKeysWith: { $1 })
        DKRequest.post(
            path: setUnlockSettingUrl,
            parameters: settingParams,
            model: BleKeyConfigModel.self) {[weak self] response in
                guard let self = self else { return }
                let resp = BleKeyConfigResponse()
                resp.code = response.code
                resp.message = response.message
                resp.data = response.data
                resp.traceId = response.traceId
                onSuccess(resp)
                if let model = response.data {
                    SQLManager.shared.insertUserSetting(uid:"\(self.uid)", vin: self.vin, model: model, completion: nil)
                }
                if response.data != nil && params.keys.contains { ["lockSettings", "enableSettings"].contains($0) } {
                    self.notifyPollingConfigDidChange(response.data!)
                }
            } onError: { response in
                response.message = "设置失败，请重试"
                onError(response.toMonaError())
            }
    }

    func checkUserSettings(
        vin: String?,
        onSuccess: ((_ response: MonaResponse<[BleKeyConfigModel]>)-> Void)?,
        onError:  MonaErrorCallback?) {
            var params = ["phoneModel": DeviceInfo.model]
            params["vin"] = vin != nil ? vin : ""
            DKRequest.post(
                path: checkUserSettingUrl,
                parameters: params,
                model: [BleKeyConfigModel].self) {[weak self] response in
                    onSuccess?(response)
                    guard let self = self else { return }
                    guard let settings = response.data, settings.count > 0 else { return }
                    for item in settings {
                        if item.vin == nil || item.vin!.isEmpty {
                            continue
                        }
                        SQLManager.shared.insertUserSetting(uid: "\(self.uid)", vin: item.vin!, model: item, completion: nil)
                        if item.vin! == self.vin {
                            self.updateCurrentBleKeyConfig(item)
                            // 发当前车辆Polling设置
                            self.notifyPollingConfigDidChange(item)
                        }
                    }
                } onError: { response in
                    onError?(response.toMonaError())
                }
        }

    // 方法没用到
    func checkCurrentCarUnlockSetting() {
        checkUserSettings(vin: vin, onSuccess: {[weak self] model in
            self?.updateCurrentBleKeyConfig(model.data?.first)
        }, onError: nil)
    }

    func updateCurrentBleKeyConfig(_ model: BleKeyConfigModel?) {
        guard let vin = model?.vin else { return }
        guard let data = model?.calibrationData else { return }
        NotificationCenter.default.post(name: .updateCalibration, object: nil, userInfo: ["vin": vin, "data": data])
    }

    func cheackAllCarUnlockSettings() {
        DKLog.log("查询所有车辆解锁配置")
        checkUserSettings(vin: nil) { respone in

        } onError: { error in

        }
    }

    private func notifyPollingConfigDidChange(_ bleKeyConfig: BleKeyConfigModel) {
        NotificationCenter.default.post(name: .monaPollingDidChange, object: nil, userInfo: ["data": bleKeyConfig])
    }

    // MARK: - 刷新钥匙

    /// 删除车辆钥匙
    /// - Parameters:
    ///   - vin: 车辆vin码
    ///   - dkId:钥匙id，可传空
    ///
    /// dkId传值时不再查询本地已缓存对应车辆钥匙，直接删除；不传时先查询本地钥匙再删除
    func deleteDigitalKey(vin: String, dkId: String? = nil, completion: ((_ result: Bool) -> Void)? = nil) {
        let deletHandler: (_ dkId: String) -> Void = {[weak self] dkId in
            guard let self = self else { return }
            DKSqlStoreUtil.xp_delete(uid: self.uid, vin: vin) { result in
                DKLog.log("直接删除本地钥匙，钥匙id：\(dkId), vin:\(vin)")
                completion?(result)
                guard result else { return }
                BleKeyHandler.reportBleKeyActiveState(vin: vin, dkId: dkId, activeCode: .delete) { result in

                }
            }
        }
        if let dkId = dkId {
            deletHandler(dkId)
        } else {
            DKSqlStoreUtil.xp_get(uid: uid, vin: vin) { bleKeyInfo in
                guard let bleKeyInfo = bleKeyInfo else {
                    completion?(false)
                    return
                }
                deletHandler(bleKeyInfo.dkId)
            }
        }
    }


    /// 删除本地钥匙
    /// - Parameters:
    ///   - uid: uid
    ///   - vin: vin
    static func deleteLocalBleKey(uid: UInt64, vin :String) {
        DKLog.log("业务调用删除本地钥匙")
        DKSqlStoreUtil.xp_get(uid: uid, vin: vin) { bleKeyInfo in
            guard let bleKeyInfo = bleKeyInfo else {
                return
            }
            DKSqlStoreUtil.xp_delete(uid: uid, vin: vin) { result in
                DKLog.log("直接删除本地钥匙，钥匙id：\(bleKeyInfo.dkId), vin:\(vin)")
                guard result else { return }
                BleKeyHandler.reportBleKeyActiveState(vin: vin, dkId: bleKeyInfo.dkId, activeCode: .delete) { result in

                }
            }
        }
    }

    // MARK: - for xp

    func xp_refreshKeys(onSuccess: BleKeyInfoListCallback? = nil, onError: MonaErrorCallback? = nil) {
        DKSqlStoreUtil.queryAllDigitalKeys(uid: uid) {[weak self] bleKeyInfos in
            self?.refreshKeys(bleKeyInfos, onSuccess: onSuccess, onError: onError)
        }
    }

    func refreshKeys(_ digitalKeys: [BleKeyInfo]?, onSuccess: BleKeyInfoListCallback? = nil, onError: MonaErrorCallback? = nil) {
        guard let digitalKeys = digitalKeys, digitalKeys.count > 0 else {
            let monaError = MonaError()
            monaError.code = -1
            monaError.message = "本地无钥匙"
            onError?(monaError)
            return
        }
        let dkList: [[String: Any]] = digitalKeys.map { dkModel in
            return [
                "dkId": dkModel.dkId,
                "updateTime": dkModel.updateTime ?? ""
            ]
        }

        DKRequest.post(
            path: getLatestDigitalKeyPath,
            parameters: ["btChainList": dkList],
            model: [BleKeyInfo].self) {[weak self] response in
                guard let self = self else { return }
                guard let bleKeyInfoList = response.data else {
                    let monaError = MonaError()
                    monaError.code = MonaErrorCode.jsonParseFail.rawValue
                    monaError.message = MonaErrorCode.jsonParseFail.msg
                    onError?(monaError)
                    return
                }
                // 如果本地钥匙不在返回的列表里就移除掉
                let newDkIds = bleKeyInfoList.map({ $0.dkId })
                digitalKeys.forEach { localModel in
                    // 返回的钥匙列表不包含或者state不为0
                    let needDelete = !newDkIds.contains(localModel.dkId) ||
                    ((newDkIds.firstIndex(of: localModel.dkId) != nil) && bleKeyInfoList[newDkIds.firstIndex(of: localModel.dkId)!].status != 0)
                    if needDelete {
                        DKLog.log("刷新钥匙-删除，vin:\(localModel.vin!), dkId: \(localModel.dkId)")
                        self.deleteDigitalKey(vin: localModel.vin!, dkId: localModel.dkId)
                        //如果是当前车辆钥匙删除，要断开蓝牙连接
                        guard localModel.vin == self.vin else { return }
                        // 判断当前是否蓝牙连接放到Seesion
                        NotificationCenter.default.post(name: .disconnectBle, object: nil, userInfo: ["vin": localModel.vin])
                    } else {
                        //本地已有的与接口返回的重合这部分，如果钥匙数据变化后要更新
                        //如果localModel与查出来的model不一样，直接覆盖保存
                        let newKeyModel = bleKeyInfoList[newDkIds.firstIndex(of: localModel.dkId)!]
                        if let vin = localModel.vin, !(localModel == newKeyModel) {
                            DKLog.log("刷新钥匙-更新，vin:\(vin), dkId: \(localModel.dkId)")
                            DKSqlStoreUtil.xp_save(uid: self.uid, vin: vin, dkModel: newKeyModel)
                        }
                    }
                }
                onSuccess?(response.toBleKeyInfoListResp())
            } onError: { response in
                onError?(response.toMonaError())
            }
    }


    func free() {
        invalidTimer()
    }

    deinit {
        invalidTimer()
    }
}

