    public func removeKey(digitalKey: DigitalKey, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {
        var keyCardType = digitalKey.keyCardType
        let plugin = self.createPlugin(keyCardType: keyCardType)
        if (plugin == nil) {
            let resp = VehicleError(code: .NotSupported, desc:"尚未支持，操作失败")
            failed(resp)
            return
        }
        self.removeKeyPlugin = plugin
        self.delegate?.willRemoveKey?(vin: self.vehicle.vin, keyCardType: keyCardType)
        plugin!.removeKey(digitalKey: digitalKey) { data in
            self.removeKeyPlugin = nil
            var keyReturned = false
            if let reponse: RemoveDigitalKeySuccessResponse = data {
                if let digitalKeyList = data?.digitalKeyList {
                    if (digitalKeyList.count ?? 0) > 0 {
                        keyReturned = true
                        for item in digitalKeyList {
                            self.removeSuccess(digitalKey: item)
                        }
                    }
                }
            }
            if keyReturned == false {
                self.removeSuccess(digitalKey: digitalKey)
            }
            self.repareBleInfo()
            self.delegate?.didRemoveKey?(vin: self.vehicle.vin, keyCardType: digitalKey.keyCardType, success: true)
            success()
        } failed: { error in
            self.removeKeyPlugin = nil
            self.delegate?.didRemoveKey?(vin: self.vehicle.vin, keyCardType: digitalKey.keyCardType, success: false)
            failed(error)
        }
    }

    func removeSuccess(digitalKey: DigitalKey){
        digitalKey.removeAllKeyMessages()
        digitalKey.remove()
        for (index, key) in self.digitalKeyList.enumerated() {
            if (key.keyCardType == digitalKey.keyCardType) {
                self.digitalKeyList.remove(at: index)
            }
        }
        self.bleInfo = nil
    }

    public func certMessageCount() -> Int {
        if let key: DigitalKey = self.validBlePrivateKey(){
            guard (key.keyCardType == KeyCardType.SELF || key.keyCardType == KeyCardType.SELF_V3) else {
                return 0;
            }
            return key.keyMessageCount();
        }
        return 0;
    }

