import Foundation

public enum BLEKeyV3HttpRequestPath: String, BLEKeyUrlProtocol {
    case deleteKey = "xp-smart-digital-key-boot/v1/app/common/delKey"                       //数字钥匙3.0私有钥匙钥匙删除
    case createKey = "xp-smart-digital-key-boot/app/ble/v1/createKey"                       //数字钥匙3.0私有钥匙创建钥匙
    case getAuthData = "xp-smart-digital-key-boot/app/ble/v1/getAuthData"                   //数字钥匙3.0私有钥匙获取证书报文
    case getKeyInfoList = "xp-smart-digital-key-boot/v1/app/common/getKeyInfoList"          //数字钥匙3.0获取钥匙列表
    case getPhone = "xp-smart-digital-key-boot/v1/app/common/getKeyInfo"                    //获取钱包钥匙的手机号
    case carKeyPassword = "xp-smart-digital-key-boot/v1/app/ccc/startPairing"               //获取carKey配对密码
    case bindUserKey = "sso/app/v5/keyAuth/userKeyBind"                                     //绑定用户与联盟钥匙的关系
    case carKeyAutoLockSetUp = "xp-smart-digital-key-boot/v1/app/common/autoLockSetUp"      //设置数字钥匙开关
    case uploadKeyCapablity = "xp-smart-digital-key-boot/v1/app/common/keyCapability"       //绑定用户与联盟钥匙的关系
    //绑定用户与联盟钥匙的关系
    case getRescueAuthData = "xp-smart-digital-key-boot/app/ble/v1/getEmergencyAuthData"

    public func urlString() -> String {
        return self.rawValue
    }
}

public enum BLEKeyV3DeviceType: Int {
    case phone = 0
    case watch = 1
    case applet = 2
}

public class SelfKeyV3Manager: DigitalKeyManagerPluginBase, DigitalKeyManagerPluginProtocol {

    required init(uid: UInt64, vehicle: VehicleInfo.Vehicle!, cardNo: String? = nil) {
        super.init(uid: uid, vehicle: vehicle, cardNo: cardNo)
    }

    deinit {
        Log.i(tag:"SelfKeyV3Manager", "deinit")
        NotificationCenter.default.removeObserver(self)
    }

    public func removeKey(digitalKey: DigitalKey, success: @escaping VehicleDigitalKeySuccessResponseCallback<RemoveDigitalKeySuccessResponse>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        deleteSelfInnovateBLEKey(cardNo: digitalKey.cardNo, vin: self.vehicle.vin ?? "" , success: success, failed: failed)
    }


    public func createKey(success: @escaping VehicleDigitalKeySuccessResponseCallback<CreateDigitalKeyListResponse>, failed: @escaping VehicleFailedCallback<CreateDigitalKeyErrorResponse>) {
        SelfKeyV3Manager.requestCreateKey(uid: self.uid, vin: self.vehicle.vin, deviceType: BLEKeyV3DeviceType.phone, success:{ data in
            let res: CreateDigitalKeyListResponse = CreateDigitalKeyListResponse()
            res.authDataList = data?.authDataList
            var list: [DigitalKey] = [DigitalKey]()
            if let key = data?.digitalKey {
                list.append(key)
            }
            res.digitalKeyList = list
            success(res)
        }, failed: failed)
    }

    public class func requestCreateKey(uid: UInt64, vin: String!, deviceType: BLEKeyV3DeviceType, success: @escaping VehicleDigitalKeySuccessResponseCallback<CreateDigitalKeyResponse>, failed: @escaping VehicleFailedCallback<CreateDigitalKeyErrorResponse>) {
        SelfKeyV3Manager.requestCreateKeyInner(vin: vin, deviceType: deviceType) { createResponse in
            if (createResponse.code == 200 && createResponse.data != nil) {
                Log.i(tag:"SelfKeyV3", "requestCreateKey 成功: \(String(describing: createResponse.data))")
                let keyInfo = createResponse.data!.keyInfo
                let card = keyInfo.modelCustomTransform()
                let key = DigitalKey(bleKeyCard: card, uid: uid, vin: vin, keyCardType: KeyCardType.SELF_V3, cardNo: keyInfo.keyId)
                let keyResp = CreateDigitalKeyResponse()
                keyResp.digitalKey = key
                SelfKeyV3Manager.getXpKeyAuthDataInner(keyId: keyInfo.keyId) { authDataResponse in
                    if authDataResponse.code == 200 && authDataResponse.data != nil && authDataResponse.data?.authDataList != nil {
                        Log.i(tag:"SelfKeyV3", "getAuthData 成功: \(String(describing: authDataResponse.data))")
                        keyResp.authDataList = [String]()
                        for authData in authDataResponse.data!.authDataList! {
                            keyResp.authDataList?.append(authData.authData ?? "")
                        }
                        success(keyResp)
                    } else {
                        Log.i(tag:"SelfKeyV3", "getAuthData 失败: \(String(describing: authDataResponse.msg))")
                        let resp = CreateDigitalKeyErrorResponse(code: Int64(authDataResponse.code), msg:authDataResponse.msg, digitalKey: nil)
                        failed(resp)
                    }
                }
            } else {
                Log.i(tag:"SelfKeyV3", "requestCreateKey 失败: \(String(describing: createResponse.msg))")
                let resp = CreateDigitalKeyErrorResponse(code: Int64(createResponse.code), msg:createResponse.msg, digitalKey: nil)
                failed(resp)
            }
        }
    }

    public class func requestCreateKeyInner(vin: String!, deviceType: BLEKeyV3DeviceType,callback: @escaping BLEKeyHttpRequestCallback<BLEKeyV3CreateKeyResultModel>) {
        BLEKeyHttpRequest.postRequest(path: BLEKeyV3HttpRequestPath.createKey, payload: ["vin":vin,"deviceType":deviceType.rawValue],callback: callback)
    }

    func activateKey(digitalKey: DigitalKey, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>){
    }

    public class func getXpKeyAuthData(uid: UInt64!, vin: String!,keyId: String!, success: @escaping VehicleDigitalKeySuccessResponseCallback<CreateDigitalKeyResponse>, failed: @escaping VehicleFailedCallback<CreateDigitalKeyErrorResponse>) {
        let key = DigitalKey(uid:uid, vin: vin ?? "", keyCardType: KeyCardType.SELF_V3, cardNo:keyId)
        let cacheMaxCount = 180;
        if key.keyMessageCount() >= cacheMaxCount {
            let keyResp = CreateDigitalKeyResponse()
            keyResp.digitalKey = key;
            success(keyResp)
            return
        }

        SelfKeyV3Manager.getXpKeyAuthDataInner(keyId: keyId, callback: { response in
            if (response.code == 200 && response.data != nil && response.data?.authDataList != nil) {
                NotificationCenter.default.post(name: VehicleNotification.DigitalKeyReceiveKeyMessageSuccess, object: nil)
                Log.i(tag:"SelfKeyV3", "getXpKeyAuthData 成功: \(String(describing: response.data))")
                let info = response.data!
                let key = DigitalKey(uid: uid, vin: vin, keyCardType: KeyCardType.SELF_V3, cardNo:keyId)
                var keyResp = CreateDigitalKeyResponse()
                keyResp.digitalKey = key;
                keyResp.authDataList = [String]()
                for authData in response.data!.authDataList! {
                    keyResp.authDataList?.append(authData.authData ?? "")
                }
                success(keyResp)
            } else {
                Log.i(tag:"SelfKeyV3", "getXpKeyAuthData 失败: \(String(describing: response.msg))")
                let resp = CreateDigitalKeyErrorResponse(code: Int64(response.code), msg:response.msg, digitalKey: nil)
                failed(resp)
            }
        })
    }

    public class func getXpKeyAuthDataInner(keyId: String!, callback: @escaping BLEKeyHttpRequestCallback<BLEKeyV3GetAuthDataResultModel>) {
        BLEKeyHttpRequest.postRequestLock(path: BLEKeyV3HttpRequestPath.getAuthData,
                                          payload: ["keyId": keyId ?? "",
                                                    "count": 200],
                                          callback: callback)
    }

    public class func getXpKeyRescueAuthData(keyId: String!, success: @escaping VehicleDigitalKeySuccessResponseCallback<GetRescueAuthKeyResponse>, failed: @escaping VehicleFailedCallback<CreateDigitalKeyErrorResponse>) {

        SelfKeyV3Manager.getXpKeyRescueAuthDataInner(keyId: keyId, callback: { response in
            if (response.code == 200 && response.data != nil && response.data?.authDataList != nil) {
                Log.i(tag:"SelfKeyV3", "getXpKeyRescueAuthData 成功: \(String(describing: response.data))")
                let info = response.data!
                var keyResp = GetRescueAuthKeyResponse()
                keyResp.keyId = keyId;
                keyResp.authDataList = [String]()
                for authData in response.data!.authDataList! {
                    keyResp.authDataList?.append(authData.authData ?? "")
                }
                success(keyResp)
            } else {
                Log.i(tag:"SelfKeyV3", "getXpKeyAuthData 失败: \(String(describing: response.msg))")
                let resp = CreateDigitalKeyErrorResponse(code: Int64(response.code), msg:response.msg, digitalKey: nil)
                failed(resp)
            }
        })
    }

    public class func getXpKeyRescueAuthDataInner(keyId: String!,callback: @escaping BLEKeyHttpRequestCallback<BLEKeyV3GetAuthDataResultModel>) {
        BLEKeyHttpRequest.postRequest(path: BLEKeyV3HttpRequestPath.getRescueAuthData, payload: ["keyId":keyId ?? "","count":1],callback: callback)
    }

    public func deleteSelfInnovateBLEKey(cardNo: String!, vin: String!, success: @escaping VehicleDigitalKeySuccessResponseCallback<RemoveDigitalKeySuccessResponse>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        SelfKeyV3Manager.deleteKeyInner(keyId: cardNo, vin: vin) { response in
            if (response.code == 200) {
                Log.i(tag:"SelfKeyV3", "SelfKeyV3Manager 解绑钥匙成功: \(String(describing: response.data))")
                let resp: RemoveDigitalKeySuccessResponse = RemoveDigitalKeySuccessResponse()
                success(resp)
            } else {
                Log.i(tag:"SelfKeyV3", "SelfKeyV3Manager 解绑钥匙失败: \(String(describing: response.msg))")
                let resp = VehicleError(code: .UnknownError, desc: response.msg)
                failed(resp)
            }
        }
    }

    public class func deleteKeyInner(keyId: String!,vin: String!, callback: @escaping BLEKeyHttpRequestCallback<DeleteDigitalKeyResponse>) {
        BLEKeyHttpRequest.postRequest(path: BLEKeyV3HttpRequestPath.deleteKey, payload: ["keyId":keyId,"vin":vin],callback: callback)
    }

    public class func requestMacAddress(vin: String!,callback: @escaping BLEKeyHttpRequestCallback<BLEInfo>) {
        BLEKeyHttpRequest.postRequest(path: BLEKeyHttpRequestPath.bleInfo, payload:["vin":vin ?? ""],callback: callback)
    }

    public func requestCardListOwn(vin: String!, uid: UInt64!, callback: @escaping BLEKeyHttpRequestCallback<RequestCardListResponse>) {
        if uid == 0 {
            let response = VehicleRequestResponse<RequestCardListResponse>()
            response.code = -1
            response.desc = "data is nil"
            response.msg = "data is nil"
            callback(response)
            return
        }
        SelfKeyV3Manager.requestCardListOwnInner(vin: vin, uid: uid) { response in
            if (response.code == 200 && response.data != nil) {
                Log.i(tag:"SelfKeyV3", "SelfKeyV3Manager 获取钥匙列表成功: \(String(describing: response.data))")
                let resp = VehicleRequestResponse<RequestCardListResponse>()
                resp.code = response.code
                resp.desc = response.desc
                resp.msg = response.msg
                resp.data = RequestCardListResponse()
                resp.data?.cardList = [BLEKeyCard]()
                resp.data?.cccVid = response.data?.cccVid
                NotificationCenter.default.post(name: VehicleNotification.kMyDigitalKeyListRequestSuccess, object: nil, userInfo: ["cccVid":response.data?.cccVid, "vin":vin])
                if response.data!.ownList != nil {
                    for v3Card in response.data!.ownList! {
                        let card = v3Card.modelCustomTransform()
                        card.vin = vin
                        card.cccVid = resp.data?.cccVid
                        resp.data?.cardList?.append(card)
                    }
                }
                if response.data!.shareList != nil {
                    for v3Card in response.data!.shareList! {
                        let card = v3Card.modelCustomTransform()
                        resp.data?.cardList?.append(card)
                    }
                }
                callback(resp)
            } else {
                Log.i(tag:"SelfKeyV3", "SelfKeyV3Manager 获取钥匙列表失败: \(String(describing: response.msg))")
                let resp = VehicleRequestResponse<RequestCardListResponse>()
                resp.code = response.code
                resp.desc = response.desc
                resp.msg = response.msg
                callback(resp)
            }
        }
    }

    public class func requestCardListOwnInner(vin: String!, uid: UInt64!, callback: @escaping BLEKeyHttpRequestCallback<BLEKeyV3GetKeyInfoListModel>) {
        BLEKeyHttpRequest.postRequest(path: BLEKeyV3HttpRequestPath.getKeyInfoList, payload:["vin":vin ?? "","userId":uid ?? 0],callback: callback)
    }
    public func clearWaitToActivate(){
    }

    public class func getCarKeyPairPassword(vin: String!,callback: @escaping BLEKeyHttpRequestCallback<CarKeyPasswordModel>) {
        BLEKeyHttpRequest.postRequest(path: BLEKeyV3HttpRequestPath.carKeyPassword, payload:["vin":vin ?? ""],callback: callback)
    }

    public func setDigitalKeySwitch(lockParam: CarKeyAutoLockRequestParam, vin: String, uid: UInt64, success: VehicleDigitalKeySuccessResponseCallback<Bool>?, failed: VehicleFailedCallback<VehicleError>?) {
        let param:[String : Any] = ["vin":vin,"uid":uid,"lockSetUp":lockParam.toDictionary()]
        BLEKeyHttpRequest.postRequest(
            path: BLEKeyV3HttpRequestPath.carKeyAutoLockSetUp,
            payload: param) {(response: VehicleRequestResponse<Bool>) in
                // 处理 response
                if response.code == 200 {
                    Log.i(tag:"SelfKeyV3", "设置数字钥匙开关成功: \(String(describing: response.data))")
                    if response.data == true {
                        success?(true)
                    }else {
                        let resp = VehicleError(code: response.code, desc: response.msg)
                        failed?(resp)
                    }
                } else {
                    Log.i(tag:"SelfKeyV3", "设置数字钥匙开关失败: \(String(describing: response.msg))")
                    let resp = VehicleError(code: response.code, desc: response.msg)
                    failed?(resp)
                }
            }
    }


    public func uploadCarkeyCapablity(keyId: String, keyCapability: CarKeyCapabilityRequestParam, success:VehicleDigitalKeySuccessResponseCallback<Bool>?, failed:VehicleFailedCallback<VehicleError>?) {
        guard let vin = self.vehicle.vin else {
            let resp = VehicleError(code: .ParamError, desc: "vin is nil")
            failed?(resp)
            return
        }
        let param = ["vin":vin, "keyId":keyId, "keyCapability":keyCapability.toDictionary()] as [String : Any]
        BLEKeyHttpRequest.postRequest(path: BLEKeyV3HttpRequestPath.uploadKeyCapablity, payload: param) { (response: VehicleRequestResponse<Bool>) in
            if response.code == 200 {
                Log.i(tag:"SelfKeyV3", "uploadCarkeyCapablity 成功: \(String(describing: response.data))")
                success?(response.data)
            } else {
                Log.i(tag:"SelfKeyV3", "uploadCarkeyCapablity 失败: \(String(describing: response.msg))")
                let resp = VehicleError(code: response.code, desc: response.msg)
                failed?(resp)
            }
        }
    }
}

import Foundation


@objc(XPDigitalKeyManagerProtocol)
public protocol DigitalKeyManagerProtocol : NSObjectProtocol {

    // 获取当前车数字钥匙列表
    var digitalKeyList: [DigitalKey] { get }

    // 指定钥匙分类获取数字钥匙
    func digitalKey(keyCategory: DigitalKeyCategory) -> DigitalKey?

    // 指定钥匙卡片类型获取数字钥匙
    func digitalKey(keyCardType: KeyCardType) -> DigitalKey?

    // 指定钥匙卡片类型获取数字钥匙列表原始数据（字典）
    func digitalKeyList(keyCardType: KeyCardType) -> Array<Any>?

    // 指定钥匙卡片类型获取数字钥匙列表
    func digitalKeyListObject(keyCardType: KeyCardType) -> [DigitalKey]?

    // 指定多个钥匙卡片类型获取数字钥匙列表
    func digitalMultiKeyList(keyCardTypeArray: Array<NSNumber>) -> Array<Any>?

    var isTboxBad: Bool { get } // 是否TBOX异常标志

    // 自动查找有效的私有蓝牙钥匙
    func validBlePrivateKey() -> DigitalKey?

    // 是否存在待激活的数字钥匙
    func existToBeActivateBLEKey() -> Bool

    // 是否存在可用的私有蓝牙钥匙
    func existValidBlePrivateKey() -> Bool

    // 是否存在可用的蓝牙钥匙
    func existValidBleKey() -> Bool

    //禁用安全钥匙，转证书钥匙
    func disableSafeKey()

    //可用的蓝牙钥匙类型
    func vaildBleKeyCategory() -> DigitalKeyCategory 

    // 设置所以指令是否免生物识别验证，默认否（用户在弹窗设置后本地缓存）
    func configNoBioVerfy(noBioVerfy: Bool)

    // 指定钥匙分类创建钥匙，目前只支持手机蓝牙自研钥匙（PHONE_BLE_KEY）
    func createKey(keyCategory: DigitalKeyCategory, success: @escaping VehicleDigitalKeySuccessResponseCallback<DigitalKey>, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 指定钥匙分类删除钥匙，目前只支持手机蓝牙自研钥匙（PHONE_BLE_KEY）
    func removeKey(keyCategory: DigitalKeyCategory, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)
    // 创建数字钥匙
    func createKey(keyCardType: KeyCardType, success: @escaping VehicleDigitalKeySuccessResponseCallback<DigitalKey>, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 创建数字蓝牙钥匙（PHONE_BLE_KEY）
    func createKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 删除数字蓝牙钥匙
    func removeKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    // 删除NFC钥匙
    func removeNfcKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    //通过网络接口设置解闭锁开关，仅用于CCC钥匙
    func setDigitalKeySwitch(lockParam: CarKeyAutoLockRequestParam, vin: String, uid: UInt64, success:  ((Bool) -> Void)?, failed: ((VehicleError) -> Void)?)

    func refreshRemoteKeyList()

    // 报文失效，清理本地数据
    func clearKeyMessage()
    var selfCalibration: PollingSelfCalibrationProtocol? { get }

    // polling 开关状态变更
    func pollingStateChange(pollingMode: VehiclePollingMode)

    func pollingEnableSwitchChange(pollingEnableSwitch: Bool) // pollingEnable 开关状态变更

    // polling 解锁距离变更
    func pollingUnlockDistanceChange(unlockDistance: Float)

    // polling 闭锁距离变更
    func pollingLockDistanceChange(lockDistance: Float)

    // polling 感应模式变更
    func pollingWelcomeModeChange(welcomeMode: Bool)

    // polling 自标定数据变更
    func pollingSelfCalibrationDataChange(txPowerArray: Array<String>?)

    /// 获取数字钥匙云端设置
    /// - Parameters:
    ///   - vin: 车架号
    ///   - device: 移动设备型号，用于区分不同设备的设置
    ///   - success: 成功回调
    ///   - failed: 失败回调
    func requestKeySettings(vin: String, device: String?, success: @escaping VehicleDigitalKeySuccessResponseCallback<KeySettingInfo>, failed: @escaping VehicleFailedCallback<VehicleError>)

    /// 上传数字钥匙设置到云端
    /// - Parameters:
    ///   - vin: 车架号
    ///   - device: 移动设备型号，用于区分不同设备的设置
    ///   - settings: 设置内容
    ///   - success: 成功回调
    ///   - failed: 失败回调
    func uploadKeySettings(vin: String, device: String?, settings: KeySettingInfo, success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>)

    //当前报文剩余数量，用于一些特定场景策略
    func certMessageCount() -> Int

    // 非数字钥匙3.0车型 非E28车可用
    func setIsDriverMode(_ isDriverMode: Bool) // 设置是否主驾模式

    func getCurrentCarKeyPlugin() -> CarKeyPassAccessProtocol?

}

