import Foundation
import XPVehicleSDK

public enum CarKeyHttpRequestPath: String, BLEKeyUrlProtocol {
    case getPhone = "xp-smart-digital-key-boot/v1/app/common/getKeyInfo"                    //获取钱包钥匙的手机号
    case carKeyPassword = "xp-smart-digital-key-boot/v1/app/ccc/startPairing"               //获取carKey配对密码
    case bindUserKey = "sso/app/v5/keyAuth/userKeyBind"                                     //绑定用户与联盟钥匙的关系
    case carKeyAutoLockSetUp = "xp-smart-digital-key-boot/v1/app/common/autoLockSetUp"      //设置数字钥匙开关
    case uploadKeyCapablity = "xp-smart-digital-key-boot/v1/app/common/keyCapability"       //绑定用户与联盟钥匙的关系

    public func urlString() -> String {
        return self.rawValue
    }
}

public class CarkeyService: NSObject, CarKeyServiceProtocol {
    //绑定钥匙到用户
    public func bindCarKeyToUser(keyId: String?, vin: String?, success: VehicleSuccessCallback?, failed: VehicleFailedCallback<VehicleError>?) {
        guard let keyId = keyId, !keyId.isEmpty else {
            let resp = VehicleError(code: .ParamError, desc: "keyId不能为空")
            failed?(resp)
            return
        }
        guard let vin = vin, !vin.isEmpty else {
            let resp = VehicleError(code: .ParamError, desc: "vin不能为空")
            failed?(resp)
            return
        }
        let param = ["vin":vin, "keyId":keyId] as [String : Any]
        BLEKeyHttpRequest.postRequest(path: CarKeyHttpRequestPath.bindUserKey, payload: param) { (response: VehicleRequestResponse<Bool>) in
            if response.code == 200 {
                Log.i(tag:"CarKey", "bindCarKeyToUser 成功: \(String(describing: response.data))")
                success?()
            } else {
                Log.i(tag:"CarKey", "bindCarKeyToUser 失败: \(String(describing: response.msg))")
                let resp = VehicleError(code: response.code, desc: response.msg)
                failed?(resp)
            }
        }
    }

    public func uploadCarkeyCapablity(keyId: String?, vin: String?, keyCapability: CarKeyCapabilityRequestParam, success:VehicleSuccessCallback?, failed:VehicleFailedCallback<VehicleError>?) {
        guard let keyId = keyId, !keyId.isEmpty else {
            let resp = VehicleError(code: .ParamError, desc: "keyId不能为空")
            failed?(resp)
            return
        }
        guard let vin = vin, !vin.isEmpty else {
            let resp = VehicleError(code: .ParamError, desc: "vin不能为空")
            failed?(resp)
            return
        }
        let param = ["vin":vin, "keyId":keyId, "keyCapability":keyCapability.toDictionary()] as [String : Any]
        BLEKeyHttpRequest.postRequest(path: CarKeyHttpRequestPath.uploadKeyCapablity, payload: param) { (response: VehicleRequestResponse<Bool>) in
            if response.code == 200 {
                Log.i(tag:"CarKey", "uploadCarkeyCapablity 成功: \(String(describing: response.data))")
                success?()
            } else {
                Log.i(tag:"CarKey", "uploadCarkeyCapablity 失败: \(String(describing: response.msg))")
                let resp = VehicleError(code: response.code, desc: response.msg)
                failed?(resp)
            }
        }
    }
}

