92	
93	        // 接口返回存在远程的值
94	        if ([self.remoteDict[@"isDriverMode"] isKindOfClass:[NSNumber class]]) {
95	            
96	            if (self.localModel) {
97	                // 允许同步一次远程数据到 isDriverMode 本地数据，否则以本地值优先
98	                self.localModel.sourceMap.isDriverModeSource = KeySettingDataSourceDefault;
