105	// BadCase: 手动设置过的乘客模式，卸载App后也一样会命中修复。建议：大于某个版本后去掉这个逻辑
106	- (RACSignal *)fixPassengerModel {
107	//    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
108	//        [subscriber sendCompleted];
109	//        return nil;
110	//    }];
111	    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
112	        MMKV *kv = [self getUserInfoMMKV:[self getUserInfoDict]];
113	        NSString *fixDriverModeKey = [kSelfDefinedIsDriverMode stringByAppendingString:@"_fix"];
114	        BOOL isDriverModeFix = [kv getBoolForKey:fixDriverModeKey defaultValue:NO];
115	        DLogTagInfo(kBLEKeySettingTag, @"开始修复主驾模式，判断是否已修复过:%d",isDriverModeFix);
116	        if (!isDriverModeFix) {
117	            if (self.remoteDict != nil &&
118	                (
119	//                 ([self.remoteDict[@"isDriverModePatch"] isKindOfClass:[NSNumber class]] &&
120	//                 [self.remoteDict[@"isDriverModePatch"] intValue] == 0) ||
121	                ([self.remoteDict[@"isDriverMode"] isKindOfClass:[NSNumber class]] &&
122	                 [self.remoteDict[@"isDriverMode"] intValue] == 0))) {
123	                DLogTagInfo(kBLEKeySettingTag, @"旧版本的为主驾模式: 0");
124	                @weakify(self)
125	                // 上传修复，删除远端的。isDriverMode 字段
126	                return [[self uploadToFixIsDriverMode] subscribeError:^(NSError * _Nullable error) {
127	                    [subscriber sendError:error];
128	                } completed:^{
129	                    @strongify(self)
130	                    if (self.remoteModel) {
131	                        self.remoteModel.isDriverMode = YES; // 默认值
132	                    }
133	                    if (self.localModel) {
134	                        self.localModel.isDriverMode = YES; // 默认值
135	                    }
136	                    if ([kv containsKey:kSelfDefinedIsDriverMode]) {
137	                        // 删除旧字段
138	                        DLogTagInfo(kBLEKeySettingTag, @"本地旧字段存在，删除旧版本 isDriverMode");
139	                        [kv removeValueForKey:kSelfDefinedIsDriverMode];
140	                    }
141	                    // 修复成功的flag
142	                    [kv setBool:YES forKey:fixDriverModeKey];
143	                    DLogTagInfo(kBLEKeySettingTag, @"修复主驾模式成功，删除旧字段，本地使用默认true");
144	                    [subscriber sendCompleted];
145	                }];
146	            } else {
147	                if (self.remoteDict == nil || ![self.remoteDict[@"isDriverMode"] isKindOfClass:[NSNumber class]]) {
148	                    // isDriverMode 旧字段不存在，未使用过5.5.1版本改过Polling设置 或者 单独设置过isDriverMode，不需要修复！
149	                    DLogTagInfo(kBLEKeySettingTag, @"数据未污染，不需要修复");
150	                    [kv setBool:YES forKey:fixDriverModeKey];
151	                }
152	                [subscriber sendCompleted];
153	                return nil;
154	            }
155	        } else {
156	            [subscriber sendCompleted];
157	            return nil;
158	        }
