231	- (RACSignal *)getKeySettingLocalDataV2 {
232	    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
233	        XPKeySettingDataV2Model *v2Model = [[XPKeySettingDataV2Model alloc]init];
234	        MMKV *kv = [self getUserInfoMMKV:[self getUserInfoDict]];
235	        
236	        if ([kv containsKey: kConfigPollingSetting]) {
237	            v2Model.sourceMap.sensitivitySource = KeySettingDataSourceLocal;
238	            v2Model.sensitivity = [kv getBoolForKey:kConfigPollingSetting defaultValue:NO];
239	        }else {
240	            if ([[MMKV mmkvWithDefaultCarVin] containsKey: kConfigPollingSetting]) {
241	                v2Model.sourceMap.sensitivitySource = KeySettingDataSourceLocal;
242	                v2Model.sensitivity = [[MMKV mmkvWithDefaultCarVin] getBoolForKey:kConfigPollingSetting defaultValue:NO];
243	            }else {
244	                NSNumber *preResult = [[NSUserDefaults standardUserDefaults] valueForKey:kConfigPollingSetting];
245	                if (preResult) {
246	                    v2Model.sourceMap.sensitivitySource = KeySettingDataSourceLocal;
247	                    v2Model.sensitivity = [preResult boolValue];
248	                }
249	            }
250	        }
251	        
252	        if ([kv containsKey:kLoginBigScreenSetting]) {
253	            v2Model.sourceMap.unlockLoginSource = KeySettingDataSourceLocal;
254	            v2Model.unlockLogin = (NSInteger)[kv getBoolForKey:kLoginBigScreenSetting defaultValue:true];
255	        } else {
256	            if ([[MMKV mmkvWithVin:self.vin] containsKey:kLoginBigScreenSetting]) {
257	                v2Model.sourceMap.unlockLoginSource = KeySettingDataSourceLocal;
258	                v2Model.unlockLogin = (NSInteger)[[MMKV mmkvWithVin:self.vin] getBoolForKey:kLoginBigScreenSetting defaultValue:true];
259	            }
260	        }
261	        if ([kv containsKey:kPollingUnlockWithWelcome]) {
262	            v2Model.sourceMap.welcomeModeSource = KeySettingDataSourceLocal;
263	            v2Model.welcomeMode = (NSInteger)[kv getBoolForKey:kPollingUnlockWithWelcome defaultValue:TRUE];
264	        }
265	        
266	        if ([kv containsKey:kBleKeyPollingLockSound]) {
267	            v2Model.sourceMap.lockSoundSource = KeySettingDataSourceLocal;
268	            v2Model.lockSound = (NSInteger)[kv getBoolForKey:kBleKeyPollingLockSound defaultValue:TRUE];
269	        } else {
270	            if ([[MMKV mmkvWithVin:self.vin] containsKey:kBleKeyPollingLockSound]) {
271	                v2Model.sourceMap.lockSoundSource = KeySettingDataSourceLocal;
272	                v2Model.lockSound = (NSInteger)[[MMKV mmkvWithVin:self.vin] getBoolForKey:kBleKeyPollingLockSound defaultValue:true];
273	            }
274	        }
275	        if ([kv containsKey:kSelfUserDefinedDistance]) {
276	            v2Model.sourceMap.unlockDistanceSource = KeySettingDataSourceLocal;
277	            v2Model.userUnlockDistance = [kv getObjectOfClass:[NSNumber class] forKey:kSelfUserDefinedDistance];
278	        } else {
279	            if ([kv containsKey:kSelfDefinedDistance]) {
280	                float unlockDistance = [kv getFloatForKey:kSelfDefinedDistance defaultValue:kDefaultUnlockDistance];
281	                if (unlockDistance != kDefaultUnlockDistance && unlockDistance != 0) {
282	                    v2Model.sourceMap.unlockDistanceSource = KeySettingDataSourceLocal;
283	                    v2Model.userUnlockDistance = @(unlockDistance);
284	                    [kv setObject:v2Model.userUnlockDistance forKey:kSelfUserDefinedDistance];
285	                    [kv sync];
286	                }
287	            }
288	        }
289	        
290	        // private key
291	        if ([self.kv containsKey:kSelfDefinedPollingEnableSwitch]) {
292	            v2Model.sourceMap.pollingEnableSwitchSource = KeySettingDataSourceLocal;
293	            v2Model.enablePE = [NSNumber numberWithBool:[self.kv getBoolForKey:kSelfDefinedPollingEnableSwitch defaultValue:ENABLE_PE]];
294	        }
295	        
296	        if ([self.kv containsKey:kSelfDefinedPollingUnLockSwitch]) {
297	            v2Model.sourceMap.pollingUnlockSource = KeySettingDataSourceLocal;
298	            v2Model.pollingUnlock = [NSNumber numberWithBool:[kv getBoolForKey:kSelfDefinedPollingUnLockSwitch defaultValue:kPrivateKeyDefaultUnLock]];
299	        }else {
300	            if ([XPCSecondPollingDataHandler pollingModeIsExistInLocal]) {
301	                v2Model.sourceMap.pollingUnlockSource = KeySettingDataSourceLocal;
302	                v2Model.pollingUnlock = [NSNumber numberWithBool:[XPCSecondPollingDataHandler pollingUnlock]];
303	            }
304	        }
305	        
306	        if ([self.kv containsKey:kSelfDefinedPollingLockSwitch]) {
307	            v2Model.sourceMap.pollingLockSource = KeySettingDataSourceLocal;
308	            v2Model.pollingLock = [NSNumber numberWithBool:[kv getBoolForKey:kSelfDefinedPollingLockSwitch defaultValue:kPrivateKeyDefaultLock]];
309	        }else {
310	            if ([XPCSecondPollingDataHandler pollingModeIsExistInLocal]) {
311	                v2Model.sourceMap.pollingLockSource = KeySettingDataSourceLocal;
312	                v2Model.pollingLock = [NSNumber numberWithBool:[XPCSecondPollingDataHandler pollingLock]];
313	            }
314	        }
315	        
316	        //carkey
317	        if ([self.kv containsKey:kCarKeyPollingEnable]) {
318	            v2Model.sourceMap.walletPollingEnableSource = KeySettingDataSourceLocal;
319	            v2Model.walletKeyPe = [NSNumber numberWithBool:[self.kv getBoolForKey:kCarKeyPollingEnable defaultValue:ENABLE_PE]];
320	        }else {
321	            // 同步旧App版本的PE开关到钱包钥匙，旧版本PE开关同时代表私有钥匙和钱包钥匙的开关
322	            if ([self.kv containsKey:kSelfDefinedPollingEnableSwitch]) {
323	                v2Model.sourceMap.walletPollingEnableSource = KeySettingDataSourceLocal;
324	                BOOL pe = [self.kv getBoolForKey:kSelfDefinedPollingEnableSwitch defaultValue:ENABLE_PE];
325	                v2Model.walletKeyPe = @(pe);
326	                [self.kv setBool:pe forKey:kCarKeyPollingEnable];
327	                [self.kv sync];
328	            }
329	        }
330	
331	        if ([self.kv containsKey:kCarKeyLock]) {
332	            v2Model.sourceMap.walletPollingLockSource = KeySettingDataSourceLocal;
333	            v2Model.walletKeyAutoLock = [NSNumber numberWithBool:[self.kv getBoolForKey:kCarKeyLock defaultValue:kWalletKeyDefaultLock]];
334	        }
335	        
336	        if ([kv containsKey:kCarKeyUnLock]) {
337	            v2Model.sourceMap.walletPollingUnlockSource = KeySettingDataSourceLocal;
338	            v2Model.walletKeyAutoUnlock = [NSNumber numberWithBool:[kv getBoolForKey:kCarKeyUnLock defaultValue:kWalletKeyDefaultUnLock]];
339	        }
340	        
341	        if ([kv containsKey:kSelfDefinedTxPower]) {
342	            v2Model.sourceMap.selfCalibrationSource = KeySettingDataSourceLocal;
343	            NSArray *txpowerArray = [kv getObjectOfClass:[NSArray class] forKey:kSelfDefinedTxPower];
344	            if (txpowerArray.count > 0) {
345	                if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
346	                    v2Model.selfCalibrationV3 = [self covertOldV3DataToNew:txpowerArray];
347	                } else {
348	                    v2Model.selfCalibrationV2 = [self covertOldV2DataToNew:txpowerArray];
349	                }
350	            }
351	        }
352	        if ([kv containsKey:kSelfDefinedIsDriverMode]) {
353	            v2Model.sourceMap.isDriverModeSource = KeySettingDataSourceLocal;
354	            v2Model.isDriverMode = [kv getBoolForKey:kSelfDefinedIsDriverMode defaultValue:TRUE];
355	        } else {
356	            v2Model.isDriverMode = TRUE; // 默认值 true
357	        }
358	
359	        DLogTagInfo(kBLEKeySettingTag, @"syncTool local pe:%@ pollingLock:%@ pollingUnlock:%@ walletPE:%@ walletLock:%@ walletUnlock:%@",v2Model.enablePE,v2Model.pollingLock,v2Model.pollingUnlock,v2Model.walletKeyPe, v2Model.walletKeyAutoLock,v2Model.walletKeyAutoUnlock);
360	
361	        self.localModel = v2Model;
362	        [subscriber sendCompleted];
363	        return nil;
364	    }];
365	}
366	
367	- (void)dealWithFetchResposeV1:(Response * _Nullable)x {
368	    if (![x.originalData isKindOfClass:[NSDictionary class]]) return;
369	    
370	    NSDictionary *data = x.originalData;
371	    NSDictionary *dataInner = data[@"data"];
372	    if (![dataInner isKindOfClass:[NSDictionary class]]) return;
373	    NSDictionary *dict = nil;
374	    NSArray *arrRecorded = nil;
375	    if (self.isInternational) {
376	        arrRecorded = dataInner[@"pollingSetting"];
377	    } else {
378	        dict = dataInner[@"BLE_KEY_POLLING"];
379	        if (![dict isKindOfClass:[NSDictionary class]]) return;
380	        arrRecorded = dict[@"pollingSetting"];
381	    }
382	    if (![arrRecorded isKindOfClass:[NSArray class]]) return;
383	    XPKeySettingDataV1Model *v1Model = nil;
384	    if (arrRecorded.count >0 ) {
385	        NSArray<XPKeySettingDataV1Model *> *deviceArray = [NSArray yy_modelArrayWithClass:XPKeySettingDataV1Model.class json:arrRecorded];
386	        //本地有未同步的缓存
