402	            if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
403	                v2Model.selfCalibrationV3 = [self covertOldV3DataToNew:v1Model.txPowerArrayOpt];
404	            } else {
