413	- (RACSignal *)dealWithFetchResposeV2:(Response * _Nullable)x {
414	    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
415	        if (![x.originalData isKindOfClass:[NSDictionary class]]) {
416	            NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkDataError userInfo:nil];
417	            [subscriber sendError:error];
418	            return nil;
419	        }
420	        if (![x.data isKindOfClass:[NSDictionary class]]) {
421	            NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkDataIsNull userInfo:nil];
422	            [subscriber sendError:error];
423	            return nil;
424	        } else {
425	            NSDictionary *data = (NSDictionary *)x.data;
426	            if (data.allKeys.count == 0) {
427	                NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkDataIsNull userInfo:nil];
428	                [subscriber sendError:error];
429	                return nil;
430	            }
431	        }
432	        XPKeySettingDataV2Model * deviceData = [XPKeySettingDataV2Model yy_modelWithDictionary:x.data];
433	        self.remoteDict = x.data;
434	        self.remoteModel = deviceData;
435	        DLogTagInfo(kBLEKeySettingTag, @"syncTool remote:%@",x.data);
436	        [subscriber sendCompleted];
437	        return nil;
438	    }];
439	}
