1069	- (NSArray *)covertOldV2DataToNew:(NSArray *)txPowerArray {
1070	    if (![txPowerArray isKindOfClass:[NSArray class]]) {
1071	        return nil;
1072	    }
1073	    if (txPowerArray.count == 0) {
1074	        return nil;
1075	    }
1076	    NSDictionary *firstObject = (NSDictionary *)txPowerArray.firstObject;
1077	    if (![firstObject isKindOfClass:[NSDictionary class]]) {
1078	        return nil;
1079	    }
1080	    if ([firstObject objectForKey:@"direction"] == 0) {
1081	        NSArray *oldLocalArray = [NSArray yy_modelArrayWithClass:[XPTxPowerRssiModel class] json:txPowerArray];
1082	        NSMutableArray<XPTxPowerModelV2 *> *selfCalibrationV2 = [NSMutableArray array];
1083	        XPTxPowerModelV2 *frontModel = [[XPTxPowerModelV2 alloc]init];
1084	        frontModel.direction = 2;
1085	        XPTxPowerModelV2 *backModel = [[XPTxPowerModelV2 alloc]init];
1086	        backModel.direction = 6;
1087	        NSMutableArray<XPTxPowerRssiModel *> *frontTmpArray = [NSMutableArray array];
1088	        NSMutableArray<XPTxPowerRssiModel *> *backTmpArray = [NSMutableArray array];
1089	        for (XPTxPowerRssiModel *rssiModel in oldLocalArray) {
1090	            if (rssiModel.txPower < 0) {
1091	                if ([rssiModel.name isEqualToString:@"BLE"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLE")]) {
1092	                    rssiModel.name = @"BLE";
1093	                    [frontTmpArray addObject:rssiModel];
1094	                } else if ([rssiModel.name isEqualToString:@"BLEFL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFL")]) {
1095	                    rssiModel.name = @"BLEFL";
1096	                    [frontTmpArray addObject:rssiModel];
1097	                } else if ([rssiModel.name isEqualToString:@"BLEFR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFR")]) {
1098	                    rssiModel.name = @"BLEFR";
1099	                    [frontTmpArray addObject:rssiModel];
1100	                } else if ([rssiModel.name isEqualToString:@"BLER"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLER")]) {
1101	                    rssiModel.name = @"BLER";
1102	                    [backTmpArray addObject:rssiModel];
1103	                } else if ([rssiModel.name isEqualToString:@"BLERL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERL")]) {
1104	                    rssiModel.name = @"BLERL";
1105	                    [backTmpArray addObject:rssiModel];
1106	                } else if ([rssiModel.name isEqualToString:@"BLERR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERR")]) {
1107	                    rssiModel.name = @"BLERR";
1108	                    [backTmpArray addObject:rssiModel];
1109	                }
1110	            }
1111	        }
1112	        if (frontTmpArray.count > 0 && backTmpArray.count > 0) {
1113	            frontModel.txPowerArray = [frontTmpArray copy];
1114	            backModel.txPowerArray = [backTmpArray copy];
1115	            [selfCalibrationV2 addObject:frontModel];
1116	            [selfCalibrationV2 addObject:backModel];
1117	            return [selfCalibrationV2 copy];
1118	        } else {
1119	            return nil;
1120	        }
1121	    } else {
1122	        NSArray<XPTxPowerModelV2 *> *selfCalibrationV2 = [NSArray yy_modelArrayWithClass:XPTxPowerModelV2.class json:txPowerArray];
1123	        NSMutableArray *tempTotalArray = [NSMutableArray array];
1124	        for (XPTxPowerModelV2 *directionModel in selfCalibrationV2) {
1125	            NSMutableArray *tempArray = [NSMutableArray array];
1126	            for (XPTxPowerRssiModel *rssiModel  in directionModel.txPowerArray) {
1127	                if (rssiModel.txPower < 0) {
1128	                    if ([rssiModel.name isEqualToString:@"BLE"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLE")]) {
1129	                        rssiModel.name = @"BLE";
1130	                        [tempArray addObject:rssiModel];
1131	                    } else if ([rssiModel.name isEqualToString:@"BLEFL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFL")]) {
1132	                        rssiModel.name = @"BLEFL";
1133	                        [tempArray addObject:rssiModel];
1134	                    } else if ([rssiModel.name isEqualToString:@"BLEFR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFR")]) {
1135	                        rssiModel.name = @"BLEFR";
1136	                        [tempArray addObject:rssiModel];
1137	                    } else if ([rssiModel.name isEqualToString:@"BLER"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLER")]) {
1138	                        rssiModel.name = @"BLER";
1139	                        [tempArray addObject:rssiModel];
1140	                    } else if ([rssiModel.name isEqualToString:@"BLERL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERL")]) {
1141	                        rssiModel.name = @"BLERL";
1142	                        [tempArray addObject:rssiModel];
1143	                    } else if ([rssiModel.name isEqualToString:@"BLERR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERR")]) {
1144	                        rssiModel.name = @"BLERR";
1145	                        [tempArray addObject:rssiModel];
1146	                    }
1147	                }
1148	            }
1149	            if (tempArray.count > 0) {
1150	                [tempTotalArray addObject:tempArray];
1151	            }
1152	        }
1153	        if (tempTotalArray.count >= selfCalibrationV2.count) {
1154	            return [selfCalibrationV2 copy];
1155	        } else {
1156	            return nil;
1157	        }
1158	    }
1159	}
