1161	- (NSArray *)covertOldV3DataToNew:(NSArray *)txPowerArray {
1162	    if (![txPowerArray isKindOfClass:[NSArray class]]) {
1163	        return nil;
1164	    }
1165	    if (txPowerArray.count == 0) {
1166	        return nil;
1167	    }
1168	    NSString *first = txPowerArray.firstObject;
1169	    if (![first isKindOfClass:[NSString class]]) {
1170	        return nil;
1171	    }
1172	    NSMutableArray *tempArray = [NSMutableArray array];
1173	    for (NSString *selfCalibrationStr in txPowerArray) {
1174	        NSCharacterSet *hexSet = [NSCharacterSet characterSetWithCharactersInString:@"0123456789abcdefABCDEF"];
1175	        NSCharacterSet *inStringSet = [NSCharacterSet characterSetWithCharactersInString:selfCalibrationStr];
1176	        if ([hexSet isSupersetOfSet:inStringSet]) {
1177	            [tempArray addObject:selfCalibrationStr];
1178	        } else {
1179	            NSData *data = [selfCalibrationStr dataUsingEncoding:NSISOLatin1StringEncoding];
1180	            [tempArray addObject:[data hexString]];
1181	        }
1182	    }
1183	    return [tempArray copy];
1184	}
