//

#import "XPKeySettingSyncTool.h"
#import "XPAPIRequestManager+Account.h"
#import "MMKV+CarValue.h"
#import "PollingEffectDefined.h"
#import "XPPollingDefined.h"

#import "XPLogTagMacro.h"
#import "NetworkMonitorManager.h"
#import "NSData+YYAdd.h"
#import "XPBleLocationDefined.h"
#import "CTMediator+CarState.h"
#import <XPPollingSDK/XPPollingSDK.h>
#import "KeyValueStore.h"

@import XPVehicleSDK;

NSString * const XPKeySettingSyncErrorDomain = @"XPKeySettingSyncErrorDomain";

PollingEffectCacheInfoKey const kCacheVinKey = @"cacheVinKey";

PollingEffectCacheInfoKey const kCacheUidKey = @"cacheUidKey";

PollingEffectCacheInfoKey const kCacheDeviceModelKey = @"cacheDeviceModelKey";

@interface XPKeySettingSyncTool ()

@property (nonatomic, copy)   NSString                   *vin;
@property (nonatomic, assign) NSInteger                  uid;
@property (nonatomic, copy)   NSString                   *deviceModel;

@property (nonatomic, copy)   NSDictionary               *remoteDict;
@property (nonatomic, strong) XPKeySettingDataV2Model    *remoteModel;
@property (nonatomic, strong) XPKeySettingDataV2Model    *localModel;

@property (nonatomic, strong) RACDisposable              *keySettingDispose;
@property (nonatomic, strong) MMKV                       *kv;

@end

@implementation XPKeySettingSyncTool

- (instancetype)initWithVin:(NSString *)vin uid:(NSInteger)uid deviceModel:(NSString *)deviceModel delegate:(nonnull id<XPKeySettingSyncDelegate>)delegate {
    if (self = [super init]) {
        _vin = vin;
        _uid = uid;
        _deviceModel = deviceModel;
        _delegate = delegate;
        [self start];
    }
    return self;
}

- (MMKV *)kv {
    if (!_kv) {
        _kv = [MMKV mmkvWithVin:self.vin userId:[NSString stringWithFormat:@"%d",self.uid] deviceModel:self.deviceModel];
    }
    return _kv;
}

- (void)start {
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(_didNetworkStatusChanged) name:NetworkStatusChangedNotificaiton object:nil];

    RACSignal * localSignal = [self getKeySettingLocalDataV2];

    [[[[localSignal
        concat:[self syncRemoteSettingDataSignal]]
       concat:[self fixPassengerModel]]
      then:^RACSignal * _Nonnull{
        if (self.remoteModel && self.remoteDataDelegate && [self.remoteDataDelegate respondsToSelector:@selector(keySettingSyncTool:didFetchRemoteData:)]) {
            [self.remoteDataDelegate keySettingTool:self didFetchRemoteData:self.remoteModel];
        }
        return [self updateRemoteSignal];
    }] subscribeError:^(NSError * _Nullable error) {
        DLogTagInfo(kBLEKeySettingTag, @"sync error:%@",error);
    } completed:^{
        DLogTagInfo(kBLEKeySettingTag, @"sync complete");
    }];
}

- (void)syncPollingSetting {
    if (self.remoteModel &&
        self.remoteDataDelegate &&
        [self.remoteDataDelegate respondsToSelector:@selector(keySettingTool:didFetchRemoteData:)]) {

        // 接口返回存在远程的值
        if ([self.remoteDict[@"isDriverMode"] isKindOfClass:[NSNumber class]]) {

            if (self.localModel) {
                // 允许同步一次远程数据到 isDriverMode 本地数据，否则以本地值优先
                self.localModel.sourceMap.isDriverModeSource = KeySettingDataSourceDefault;
            }
            [self.remoteDataDelegate keySettingTool:self didFetchRemoteData:self.remoteModel];
        }
    }
}

// BadCase: 手动设置过的乘客模式，卸载App后也一样会命中修复。建议：大于某个版本后去掉这个逻辑
- (RACSignal *)fixPassengerModel {
//    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
//        [subscriber sendCompleted];
//        return nil;
//    }];
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        MMKV *kv = [self getUserInfoMMKV:[self getUserInfoDict]];
        NSString *fixDriverModeKey = [kSelfDefinedIsDriverMode stringByAppendingString:@"_fix"];
        BOOL isDriverModeFix = [kv getBoolForKey:fixDriverModeKey defaultValue:NO];
        DLogTagInfo(kBLEKeySettingTag, @"开始修复主驾模式，判断是否已修复过:%d",isDriverModeFix);
        if (!isDriverModeFix) {
            if (self.remoteDict != nil &&
                (
//                 ([self.remoteDict[@"isDriverModePatch"] isKindOfClass:[NSNumber class]] &&
//                 [self.remoteDict[@"isDriverModePatch"] intValue] == 0) ||
                ([self.remoteDict[@"isDriverMode"] isKindOfClass:[NSNumber class]] &&
                 [self.remoteDict[@"isDriverMode"] intValue] == 0))) {
                DLogTagInfo(kBLEKeySettingTag, @"旧版本的为主驾模式: 0");
                @weakify(self)
                // 上传修复，删除远端的。isDriverMode 字段
                return [[self uploadToFixIsDriverMode] subscribeError:^(NSError * _Nullable error) {
                    [subscriber sendError:error];
                } completed:^{
                    @strongify(self)
                    if (self.remoteModel) {
                        self.remoteModel.isDriverMode = YES; // 默认值
                    }
                    if (self.localModel) {
                        self.localModel.isDriverMode = YES; // 默认值
                    }
                    if ([kv containsKey:kSelfDefinedIsDriverMode]) {
                        // 删除旧字段
                        DLogTagInfo(kBLEKeySettingTag, @"本地旧字段存在，删除旧版本 isDriverMode");
                        [kv removeValueForKey:kSelfDefinedIsDriverMode];
                    }
                    // 修复成功的flag
                    [kv setBool:YES forKey:fixDriverModeKey];
                    DLogTagInfo(kBLEKeySettingTag, @"修复主驾模式成功，删除旧字段，本地使用默认true");
                    [subscriber sendCompleted];
                }];
            } else {
                if (self.remoteDict == nil || ![self.remoteDict[@"isDriverMode"] isKindOfClass:[NSNumber class]]) {
                    // isDriverMode 旧字段不存在，未使用过5.5.1版本改过Polling设置 或者 单独设置过isDriverMode，不需要修复！
                    DLogTagInfo(kBLEKeySettingTag, @"数据未污染，不需要修复");
                    [kv setBool:YES forKey:fixDriverModeKey];
                }
                [subscriber sendCompleted];
                return nil;
            }
        } else {
            [subscriber sendCompleted];
            return nil;
        }
    }];
}

- (RACSignal *)uploadToFixIsDriverMode {
    NSMutableDictionary *biz = [NSMutableDictionary dictionary];
    if (self.remoteDict != nil) {
        [biz addEntriesFromDictionary:self.remoteDict];
    }
    if (biz.allKeys.count > 0) {
        [biz removeObjectForKey:@"isDriverMode"];
//        [biz removeObjectForKey:@"isDriverModePatch"];
//        biz[@"isDriverMode"] = @(1);
        NSMutableDictionary *params = [NSMutableDictionary dictionary];
        params[@"vin"] = self.vin;
        params[@"platformType"] = @(1);
        params[@"deviceModel"] = self.deviceModel;
        params[@"bizKey"] = @"POLLING";
        params[@"bizValue"] = biz;
        return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
            [[XPAPIRequestManager.sharedManager requestSavePollingSettingV2:params] subscribeNext:^(Response * _Nullable x) {
                if (x.isSuccess) {
                    [subscriber sendCompleted];
                } else {
                    NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkRequestError userInfo:nil];
                    [subscriber sendError:error];
                }
            } error:^(NSError * _Nullable error) {
                [subscriber sendError:error];
            }];
            return nil;
        }];
    } else {
        NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorLocalDataNotSet userInfo:nil];
        return [RACSignal error:error];
    }
}

- (RACSignal *)fetchKeySettingRemoteDataV1 {
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        RACDisposable *disposable = [[XPAPIRequestManager.sharedManager requestSelfConfigPolling] subscribeNext:^(Response * _Nullable x) {
            if (x.isSuccess) {
                DLogTagInfo(kBLEKeySettingTag, @"fetchKeySettingRemoteDataV1 success:%@",x);
                [self dealWithFetchResposeV1:x];
            } else {
                NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkRequestError userInfo:nil];
                [subscriber sendError:error];
            }
            [subscriber sendCompleted];
        } error:^(NSError * _Nullable error) {
            [subscriber sendError:error];
        }];
        return disposable;
    }];
}

- (RACSignal *)fetchKeySettingRemoteDataV2 {
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        RACDisposable *disposable = [[XPAPIRequestManager.sharedManager requestSelfConfigPollingV2:self.vin deviceModel:self.deviceModel] subscribeNext:^(Response * _Nullable x) {
            if (x.isSuccess) {
                [subscriber sendNext:x];
                [subscriber sendCompleted];
            } else {
                NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkRequestError userInfo:nil];
                [subscriber sendError:error];
            }
        } error:^(NSError * _Nullable error) {
            [subscriber sendError:error];
        }];
        return disposable;
    }];
}

- (RACSignal *)getKeySettingLocalDataV2 {
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        XPKeySettingDataV2Model *v2Model = [[XPKeySettingDataV2Model alloc]init];
        MMKV *kv = [self getUserInfoMMKV:[self getUserInfoDict]];

        if ([kv containsKey: kConfigPollingSetting]) {
            v2Model.sourceMap.sensitivitySource = KeySettingDataSourceLocal;
            v2Model.sensitivity = [kv getBoolForKey:kConfigPollingSetting defaultValue:NO];
        }else {
            if ([[MMKV mmkvWithDefaultCarVin] containsKey: kConfigPollingSetting]) {
                v2Model.sourceMap.sensitivitySource = KeySettingDataSourceLocal;
                v2Model.sensitivity = [[MMKV mmkvWithDefaultCarVin] getBoolForKey:kConfigPollingSetting defaultValue:NO];
            }else {
                NSNumber *preResult = [[NSUserDefaults standardUserDefaults] valueForKey:kConfigPollingSetting];
                if (preResult) {
                    v2Model.sourceMap.sensitivitySource = KeySettingDataSourceLocal;
                    v2Model.sensitivity = [preResult boolValue];
                }
            }
        }

        if ([kv containsKey:kLoginBigScreenSetting]) {
            v2Model.sourceMap.unlockLoginSource = KeySettingDataSourceLocal;
            v2Model.unlockLogin = (NSInteger)[kv getBoolForKey:kLoginBigScreenSetting defaultValue:true];
        } else {
            if ([[MMKV mmkvWithVin:self.vin] containsKey:kLoginBigScreenSetting]) {
                v2Model.sourceMap.unlockLoginSource = KeySettingDataSourceLocal;
                v2Model.unlockLogin = (NSInteger)[[MMKV mmkvWithVin:self.vin] getBoolForKey:kLoginBigScreenSetting defaultValue:true];
            }
        }
        if ([kv containsKey:kPollingUnlockWithWelcome]) {
            v2Model.sourceMap.welcomeModeSource = KeySettingDataSourceLocal;
            v2Model.welcomeMode = (NSInteger)[kv getBoolForKey:kPollingUnlockWithWelcome defaultValue:TRUE];
        }

        if ([kv containsKey:kBleKeyPollingLockSound]) {
            v2Model.sourceMap.lockSoundSource = KeySettingDataSourceLocal;
            v2Model.lockSound = (NSInteger)[kv getBoolForKey:kBleKeyPollingLockSound defaultValue:TRUE];
        } else {
            if ([[MMKV mmkvWithVin:self.vin] containsKey:kBleKeyPollingLockSound]) {
                v2Model.sourceMap.lockSoundSource = KeySettingDataSourceLocal;
                v2Model.lockSound = (NSInteger)[[MMKV mmkvWithVin:self.vin] getBoolForKey:kBleKeyPollingLockSound defaultValue:true];
            }
        }
        if ([kv containsKey:kSelfUserDefinedDistance]) {
            v2Model.sourceMap.unlockDistanceSource = KeySettingDataSourceLocal;
            v2Model.userUnlockDistance = [kv getObjectOfClass:[NSNumber class] forKey:kSelfUserDefinedDistance];
        } else {
            if ([kv containsKey:kSelfDefinedDistance]) {
                float unlockDistance = [kv getFloatForKey:kSelfDefinedDistance defaultValue:kDefaultUnlockDistance];
                if (unlockDistance != kDefaultUnlockDistance && unlockDistance != 0) {
                    v2Model.sourceMap.unlockDistanceSource = KeySettingDataSourceLocal;
                    v2Model.userUnlockDistance = @(unlockDistance);
                    [kv setObject:v2Model.userUnlockDistance forKey:kSelfUserDefinedDistance];
                    [kv sync];
                }
            }
        }

        // private key
        if ([self.kv containsKey:kSelfDefinedPollingEnableSwitch]) {
            v2Model.sourceMap.pollingEnableSwitchSource = KeySettingDataSourceLocal;
            v2Model.enablePE = [NSNumber numberWithBool:[self.kv getBoolForKey:kSelfDefinedPollingEnableSwitch defaultValue:ENABLE_PE]];
        }

        if ([self.kv containsKey:kSelfDefinedPollingUnLockSwitch]) {
            v2Model.sourceMap.pollingUnlockSource = KeySettingDataSourceLocal;
            v2Model.pollingUnlock = [NSNumber numberWithBool:[kv getBoolForKey:kSelfDefinedPollingUnLockSwitch defaultValue:kPrivateKeyDefaultUnLock]];
        }else {
            if ([XPCSecondPollingDataHandler pollingModeIsExistInLocal]) {
                v2Model.sourceMap.pollingUnlockSource = KeySettingDataSourceLocal;
                v2Model.pollingUnlock = [NSNumber numberWithBool:[XPCSecondPollingDataHandler pollingUnlock]];
            }
        }

        if ([self.kv containsKey:kSelfDefinedPollingLockSwitch]) {
            v2Model.sourceMap.pollingLockSource = KeySettingDataSourceLocal;
            v2Model.pollingLock = [NSNumber numberWithBool:[kv getBoolForKey:kSelfDefinedPollingLockSwitch defaultValue:kPrivateKeyDefaultLock]];
        }else {
            if ([XPCSecondPollingDataHandler pollingModeIsExistInLocal]) {
                v2Model.sourceMap.pollingLockSource = KeySettingDataSourceLocal;
                v2Model.pollingLock = [NSNumber numberWithBool:[XPCSecondPollingDataHandler pollingLock]];
            }
        }

        //carkey
        if ([self.kv containsKey:kCarKeyPollingEnable]) {
            v2Model.sourceMap.walletPollingEnableSource = KeySettingDataSourceLocal;
            v2Model.walletKeyPe = [NSNumber numberWithBool:[self.kv getBoolForKey:kCarKeyPollingEnable defaultValue:ENABLE_PE]];
        }else {
            // 同步旧App版本的PE开关到钱包钥匙，旧版本PE开关同时代表私有钥匙和钱包钥匙的开关
            if ([self.kv containsKey:kSelfDefinedPollingEnableSwitch]) {
                v2Model.sourceMap.walletPollingEnableSource = KeySettingDataSourceLocal;
                BOOL pe = [self.kv getBoolForKey:kSelfDefinedPollingEnableSwitch defaultValue:ENABLE_PE];
                v2Model.walletKeyPe = @(pe);
                [self.kv setBool:pe forKey:kCarKeyPollingEnable];
                [self.kv sync];
            }
        }

        if ([self.kv containsKey:kCarKeyLock]) {
            v2Model.sourceMap.walletPollingLockSource = KeySettingDataSourceLocal;
            v2Model.walletKeyAutoLock = [NSNumber numberWithBool:[self.kv getBoolForKey:kCarKeyLock defaultValue:kWalletKeyDefaultLock]];
        }

        if ([kv containsKey:kCarKeyUnLock]) {
            v2Model.sourceMap.walletPollingUnlockSource = KeySettingDataSourceLocal;
            v2Model.walletKeyAutoUnlock = [NSNumber numberWithBool:[kv getBoolForKey:kCarKeyUnLock defaultValue:kWalletKeyDefaultUnLock]];
        }

        if ([kv containsKey:kSelfDefinedTxPower]) {
            v2Model.sourceMap.selfCalibrationSource = KeySettingDataSourceLocal;
            NSArray *txpowerArray = [kv getObjectOfClass:[NSArray class] forKey:kSelfDefinedTxPower];
            if (txpowerArray.count > 0) {
                if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
                    v2Model.selfCalibrationV3 = [self covertOldV3DataToNew:txpowerArray];
                } else {
                    v2Model.selfCalibrationV2 = [self covertOldV2DataToNew:txpowerArray];
                }
            }
        }
        if ([kv containsKey:kSelfDefinedIsDriverMode]) {
            v2Model.sourceMap.isDriverModeSource = KeySettingDataSourceLocal;
            v2Model.isDriverMode = [kv getBoolForKey:kSelfDefinedIsDriverMode defaultValue:TRUE];
        } else {
            v2Model.isDriverMode = TRUE; // 默认值 true
        }

        DLogTagInfo(kBLEKeySettingTag, @"syncTool local pe:%@ pollingLock:%@ pollingUnlock:%@ walletPE:%@ walletLock:%@ walletUnlock:%@",v2Model.enablePE,v2Model.pollingLock,v2Model.pollingUnlock,v2Model.walletKeyPe, v2Model.walletKeyAutoLock,v2Model.walletKeyAutoUnlock);

        self.localModel = v2Model;
        [subscriber sendCompleted];
        return nil;
    }];
}

- (void)dealWithFetchResposeV1:(Response * _Nullable)x {
    if (![x.originalData isKindOfClass:[NSDictionary class]]) return;

    NSDictionary *data = x.originalData;
    NSDictionary *dataInner = data[@"data"];
    if (![dataInner isKindOfClass:[NSDictionary class]]) return;
    NSDictionary *dict = nil;
    NSArray *arrRecorded = nil;
    if (self.isInternational) {
        arrRecorded = dataInner[@"pollingSetting"];
    } else {
        dict = dataInner[@"BLE_KEY_POLLING"];
        if (![dict isKindOfClass:[NSDictionary class]]) return;
        arrRecorded = dict[@"pollingSetting"];
    }
    if (![arrRecorded isKindOfClass:[NSArray class]]) return;
    XPKeySettingDataV1Model *v1Model = nil;
    if (arrRecorded.count >0 ) {
        NSArray<XPKeySettingDataV1Model *> *deviceArray = [NSArray yy_modelArrayWithClass:XPKeySettingDataV1Model.class json:arrRecorded];
        //本地有未同步的缓存
        for (XPKeySettingDataV1Model *d in deviceArray) {
            if ([self.vin isEqualToString:d.vin] && [d.deviceModel isEqualToString:self.deviceModel]) {
                v1Model = d;
                break;
            }
        }
    }
    if (v1Model) {
        XPKeySettingDataV2Model *v2Model = [[XPKeySettingDataV2Model alloc]init];
        v2Model.welcomeMode = v1Model.welcomeMode;
        if (v1Model.customUnlockDistance != kDefaultUnlockDistance && v1Model.customUnlockDistance != 0) {
            v2Model.userUnlockDistance = @(v1Model.customUnlockDistance);
        }
        v2Model.isDriverMode = TRUE;
        if (v1Model.txPowerArrayOpt.count > 0) {
            if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
                v2Model.selfCalibrationV3 = [self covertOldV3DataToNew:v1Model.txPowerArrayOpt];
            } else {
                v2Model.selfCalibrationV2 = [self covertOldV2DataToNew:v1Model.txPowerArrayOpt];
            }
        }
        self.remoteModel = v2Model;
        DLogTagInfo(kBLEKeySettingTag, @"dealWithFetchResposeV1 complete:%@",self.remoteModel.yy_modelToJSONObject);
    }
}

- (RACSignal *)dealWithFetchResposeV2:(Response * _Nullable)x {
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        if (![x.originalData isKindOfClass:[NSDictionary class]]) {
            NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkDataError userInfo:nil];
            [subscriber sendError:error];
            return nil;
        }
        if (![x.data isKindOfClass:[NSDictionary class]]) {
            NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkDataIsNull userInfo:nil];
            [subscriber sendError:error];
            return nil;
        } else {
            NSDictionary *data = (NSDictionary *)x.data;
            if (data.allKeys.count == 0) {
                NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkDataIsNull userInfo:nil];
                [subscriber sendError:error];
                return nil;
            }
        }
        XPKeySettingDataV2Model * deviceData = [XPKeySettingDataV2Model yy_modelWithDictionary:x.data];
        self.remoteDict = x.data;
        self.remoteModel = deviceData;
        DLogTagInfo(kBLEKeySettingTag, @"syncTool remote:%@",x.data);
        [subscriber sendCompleted];
        return nil;
    }];
}

- (RACSignal *)syncRemoteSettingDataSignal {
    RACSignal * remoteSignal = [[[self fetchKeySettingRemoteDataV2] flattenMap:^__kindof RACSignal * _Nullable(id  _Nullable value) {
        DLogTagInfo(kBLEKeySettingTag, @"fetchKeySettingRemoteDataV2 success:%@",value);
        return [self dealWithFetchResposeV2:value];
    }] catch:^RACSignal * _Nonnull(NSError * _Nonnull error) {
        if ([error.domain isEqualToString:XPKeySettingSyncErrorDomain] && error.code == XPKeySettingSyncErrorNetWorkDataIsNull) {
            return [self fetchKeySettingRemoteDataV1];
        }
        return [RACSignal error:error];
    }];
    return remoteSignal;
}

- (RACSignal *)updateRemoteSignal {
    return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
        @weakify(self)
        [[self syncLocalDataToOrigin] subscribeError:^(NSError * _Nullable error) {
            [subscriber sendError:error];
        } completed:^{
            @strongify(self)
            DLogTagInfo(kBLEKeySettingTag, @"upload local data success");
            XPKeySettingDataV2Model *copyLocalModel = [self.localModel copy];
            self.remoteModel = copyLocalModel;
            [subscriber sendCompleted];
        }];
        return nil;
    }];
}

- (RACSignal *)syncLocalDataToOrigin {
    if (!self.localModel) {
        DLogTagInfo(kBLEKeySettingTag, @"local model is nil");
        NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorLocalDataIsNull userInfo:nil];
        return [RACSignal error:error];
    }
    if (self.remoteModel) {
        [self syncNetWorkToLocalData];
    } else {
        DLogTagInfo(kBLEKeySettingTag, @"remote model is nil");
    }
    return [self uploadLocalData];
}

- (RACSignal *)uploadLocalData {
    NSMutableDictionary *biz = [NSMutableDictionary dictionary];
    if (self.localModel.sourceMap.sensitivitySource == KeySettingDataSourceLocal) {
        biz[@"sensitivity"] = @(self.localModel.sensitivity);
    }
    if (self.localModel.sourceMap.unlockLoginSource == KeySettingDataSourceLocal) {
        biz[@"unlockLogin"] = @(self.localModel.unlockLogin);
    }
    if (self.localModel.sourceMap.lockSoundSource == KeySettingDataSourceLocal) {
        biz[@"lockSound"] = @(self.localModel.lockSound);
    }
    if (self.localModel.sourceMap.welcomeModeSource == KeySettingDataSourceLocal) {
        biz[@"welcomeMode"] = @(self.localModel.welcomeMode);
    }
    if (self.localModel.sourceMap.unlockDistanceSource == KeySettingDataSourceLocal) {
        biz[@"userUnlockDistance"] = self.localModel.userUnlockDistance;
    }
    if (self.localModel.sourceMap.selfCalibrationSource == KeySettingDataSourceLocal) {
        if (self.localModel.selfCalibrationV3.count > 0) {
            biz[@"selfCalibrationV3"] = self.localModel.selfCalibrationV3;
        }
        if (self.localModel.selfCalibrationV2.count > 0) {
            biz[@"selfCalibrationV2"] = [self.localModel.selfCalibrationV2 yy_modelToJSONObject];
        }
    }
    if (self.localModel.sourceMap.isDriverModeSource == KeySettingDataSourceLocal) {
        biz[@"isDriverMode"] = @(self.localModel.isDriverMode);
    }
    if (self.localModel.sourceMap.pollingEnableSwitchSource == KeySettingDataSourceLocal) {
        biz[@"enablePE"] = self.localModel.enablePE;
    }
    if (self.localModel.sourceMap.pollingUnlockSource == KeySettingDataSourceLocal) {
        biz[@"pollingUnlock"] = self.localModel.pollingUnlock;
    }
    if (self.localModel.sourceMap.pollingLockSource == KeySettingDataSourceLocal) {
        biz[@"pollingLock"] = self.localModel.pollingLock;
    }

    //wallet key
    if (self.localModel.sourceMap.walletPollingEnableSource == KeySettingDataSourceLocal) {
        biz[@"walletKeyPe"] = self.localModel.walletKeyPe;
    }
    if (self.localModel.sourceMap.walletPollingUnlockSource == KeySettingDataSourceLocal) {
        biz[@"walletKeyAutoUnlock"] = self.localModel.walletKeyAutoUnlock;
    }
    if (self.localModel.sourceMap.walletPollingLockSource == KeySettingDataSourceLocal) {
        biz[@"walletKeyAutoLock"] = self.localModel.walletKeyAutoLock;
    }

    if (biz.allKeys.count > 0) {
        NSMutableDictionary *params = [NSMutableDictionary dictionary];
        params[@"vin"] = self.vin;
        params[@"platformType"] = @(1);
        params[@"deviceModel"] = self.deviceModel;
        params[@"bizKey"] = @"POLLING";
        params[@"bizValue"] = biz;
        DLogTagInfo(kBLEKeySettingTag, @"syncTool upload params:%@",params);
        return [RACSignal createSignal:^RACDisposable * _Nullable(id<RACSubscriber>  _Nonnull subscriber) {
            [[XPAPIRequestManager.sharedManager requestSavePollingSettingV2:params] subscribeNext:^(Response * _Nullable x) {
                if (x.isSuccess) {
                    [subscriber sendCompleted];
                } else {
                    NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorNetWorkRequestError userInfo:nil];
                    [subscriber sendError:error];
                }
            } error:^(NSError * _Nullable error) {
                [subscriber sendError:error];
            }];
            return nil;
        }];
    } else {
        NSError *error = [[NSError alloc] initWithDomain:XPKeySettingSyncErrorDomain code:XPKeySettingSyncErrorLocalDataNotSet userInfo:nil];
        return [RACSignal error:error];
    }
}

