- (void)syncNetWorkToLocalData {
    if (self.localModel.sourceMap.sensitivitySource == KeySettingDataSourceDefault) {
        self.localModel.sensitivity = self.remoteModel.sensitivity;
        [self syncLocalSentivity:self.remoteModel.sensitivity];
    }

    if (self.localModel.sourceMap.unlockLoginSource == KeySettingDataSourceDefault) {
        self.localModel.unlockLogin = self.remoteModel.unlockLogin;
        [self syncLocalUnlockLoginOn:self.localModel.unlockLogin];
    }

    if (self.localModel.sourceMap.lockSoundSource == KeySettingDataSourceDefault) {
        self.localModel.lockSound = self.remoteModel.lockSound;
        [self syncLocalLockSoundOn:self.localModel.lockSound];
    }

    if (self.localModel.sourceMap.isDriverModeSource == KeySettingDataSourceDefault) {
        self.localModel.isDriverMode = self.remoteModel.isDriverMode;
        [self syncLocalIsDriverMode:self.localModel.isDriverMode];
    }

    if (self.localModel.sourceMap.welcomeModeSource == KeySettingDataSourceDefault) {
        self.localModel.welcomeMode = self.remoteModel.welcomeMode;
        [self syncLocalWelcomeModeOn:self.localModel.welcomeMode];
    }
    if (self.localModel.sourceMap.unlockDistanceSource == KeySettingDataSourceDefault) {
        if (self.remoteModel.userUnlockDistance && [self.remoteModel.userUnlockDistance floatValue] != 0) {
            self.localModel.userUnlockDistance = self.remoteModel.userUnlockDistance;
            [self syncLocalUnlockDistance:self.localModel.userUnlockDistance];
        }
    }
    if (self.localModel.sourceMap.selfCalibrationSource == KeySettingDataSourceDefault) {
        self.localModel.selfCalibrationV3 = self.remoteModel.selfCalibrationV3;
        self.localModel.selfCalibrationV2 = self.remoteModel.selfCalibrationV2;
        if (self.localModel.selfCalibrationV3) {
            [self syncLocalSelfCalibrationTxPowerArrayV3:self.localModel.selfCalibrationV3];
        }
        if (self.localModel.selfCalibrationV2) {
            [self syncLocalSelfCalibrationTxPowerArrayV2:[self.localModel.selfCalibrationV2 yy_modelToJSONObject]];
        }
    }
    if (self.remoteModel.enablePE != nil && self.localModel.sourceMap.pollingEnableSwitchSource == KeySettingDataSourceDefault) {
        self.localModel.enablePE = self.remoteModel.enablePE;
        [self syncLocalPollingEnableSwitch:self.remoteModel.enablePE.boolValue];
    }
    if (self.remoteModel.pollingUnlock != nil && self.localModel.sourceMap.pollingUnlockSource == KeySettingDataSourceDefault) {
        [self syncLocalPollingUnlock:self.remoteModel.pollingUnlock];
    }
    if (self.remoteModel.pollingLock != nil && self.localModel.sourceMap.pollingLockSource == KeySettingDataSourceDefault) {
        [self syncLocalPollingLock:self.remoteModel.pollingLock];
    }

    //wallet key
    if (self.remoteModel.walletKeyPe != nil && self.localModel.sourceMap.walletPollingEnableSource == KeySettingDataSourceDefault) {
        [self syncLocalWalletPE:self.remoteModel.walletKeyPe];
    }

    if (self.remoteModel.walletKeyAutoUnlock != nil && self.localModel.sourceMap.walletPollingUnlockSource == KeySettingDataSourceDefault) {
        [self syncLocalWalletKeyUnlock:self.remoteModel.walletKeyAutoUnlock];
    }

    if (self.remoteModel.walletKeyAutoLock != nil && self.localModel.sourceMap.walletPollingLockSource == KeySettingDataSourceDefault) {
        [self syncLocalWalletKeyLock:self.remoteModel.walletKeyAutoLock];
    }
}

