- (float)getUnlockDistance {
    float unlockDistance = kDefaultUnlockDistance;
    bool isHidden = false;
    NSDictionary *dynamicConfig = [self getDynamicConfig];
    if (dynamicConfig[kOcmDynamicUnlockDistance]) {
        unlockDistance = [dynamicConfig[kOcmDynamicUnlockDistance] floatValue];
    }
    if (dynamicConfig[kOcmDynamicDistanceEditBarIsHidden]) {
        isHidden = ![dynamicConfig[kOcmDynamicDistanceEditBarIsHidden] boolValue];
    }
    if (!isHidden) {
        if (self.localModel) {
            if (self.localModel.sourceMap.unlockDistanceSource == KeySettingDataSourceLocal) {
                unlockDistance = [self.localModel.userUnlockDistance floatValue];
            }
        } else {
            MMKV *kv = [self getUserInfoMMKV:[self getUserInfoDict]];
            if ([kv containsKey:kSelfUserDefinedDistance]) {
                unlockDistance = [[kv getObjectOfClass:[NSNumber class] forKey:kSelfUserDefinedDistance] floatValue];
            } else {
                if ([kv containsKey:kSelfDefinedDistance]) {
                    float distance = [kv getFloatForKey:kSelfDefinedDistance defaultValue:kDefaultUnlockDistance];
                    if (distance != kDefaultUnlockDistance && distance != 0) {
                        unlockDistance = distance;
                    }
                }
            }
        }
    }
    DLogTagInfo(kBLEKeySettingTag, @"获取用户设置解锁距离:%f",unlockDistance);
    return unlockDistance;
}

