- (NSArray *)covertOldV2DataToNew:(NSArray *)txPowerArray {
    if (![txPowerArray isKindOfClass:[NSArray class]]) {
        return nil;
    }
    if (txPowerArray.count == 0) {
        return nil;
    }
    NSDictionary *firstObject = (NSDictionary *)txPowerArray.firstObject;
    if (![firstObject isKindOfClass:[NSDictionary class]]) {
        return nil;
    }
    if ([firstObject objectForKey:@"direction"] == 0) {
        NSArray *oldLocalArray = [NSArray yy_modelArrayWithClass:[XPTxPowerRssiModel class] json:txPowerArray];
        NSMutableArray<XPTxPowerModelV2 *> *selfCalibrationV2 = [NSMutableArray array];
        XPTxPowerModelV2 *frontModel = [[XPTxPowerModelV2 alloc]init];
        frontModel.direction = 2;
        XPTxPowerModelV2 *backModel = [[XPTxPowerModelV2 alloc]init];
        backModel.direction = 6;
        NSMutableArray<XPTxPowerRssiModel *> *frontTmpArray = [NSMutableArray array];
        NSMutableArray<XPTxPowerRssiModel *> *backTmpArray = [NSMutableArray array];
        for (XPTxPowerRssiModel *rssiModel in oldLocalArray) {
            if (rssiModel.txPower < 0) {
                if ([rssiModel.name isEqualToString:@"BLE"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLE")]) {
                    rssiModel.name = @"BLE";
                    [frontTmpArray addObject:rssiModel];
                } else if ([rssiModel.name isEqualToString:@"BLEFL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFL")]) {
                    rssiModel.name = @"BLEFL";
                    [frontTmpArray addObject:rssiModel];
                } else if ([rssiModel.name isEqualToString:@"BLEFR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFR")]) {
                    rssiModel.name = @"BLEFR";
                    [frontTmpArray addObject:rssiModel];
                } else if ([rssiModel.name isEqualToString:@"BLER"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLER")]) {
                    rssiModel.name = @"BLER";
                    [backTmpArray addObject:rssiModel];
                } else if ([rssiModel.name isEqualToString:@"BLERL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERL")]) {
                    rssiModel.name = @"BLERL";
                    [backTmpArray addObject:rssiModel];
                } else if ([rssiModel.name isEqualToString:@"BLERR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERR")]) {
                    rssiModel.name = @"BLERR";
                    [backTmpArray addObject:rssiModel];
                }
            }
        }
        if (frontTmpArray.count > 0 && backTmpArray.count > 0) {
            frontModel.txPowerArray = [frontTmpArray copy];
            backModel.txPowerArray = [backTmpArray copy];
            [selfCalibrationV2 addObject:frontModel];
            [selfCalibrationV2 addObject:backModel];
            return [selfCalibrationV2 copy];
        } else {
            return nil;
        }
    } else {
        NSArray<XPTxPowerModelV2 *> *selfCalibrationV2 = [NSArray yy_modelArrayWithClass:XPTxPowerModelV2.class json:txPowerArray];
        NSMutableArray *tempTotalArray = [NSMutableArray array];
        for (XPTxPowerModelV2 *directionModel in selfCalibrationV2) {
            NSMutableArray *tempArray = [NSMutableArray array];
            for (XPTxPowerRssiModel *rssiModel  in directionModel.txPowerArray) {
                if (rssiModel.txPower < 0) {
                    if ([rssiModel.name isEqualToString:@"BLE"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLE")]) {
                        rssiModel.name = @"BLE";
                        [tempArray addObject:rssiModel];
                    } else if ([rssiModel.name isEqualToString:@"BLEFL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFL")]) {
                        rssiModel.name = @"BLEFL";
                        [tempArray addObject:rssiModel];
                    } else if ([rssiModel.name isEqualToString:@"BLEFR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLEFR")]) {
                        rssiModel.name = @"BLEFR";
                        [tempArray addObject:rssiModel];
                    } else if ([rssiModel.name isEqualToString:@"BLER"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLER")]) {
                        rssiModel.name = @"BLER";
                        [tempArray addObject:rssiModel];
                    } else if ([rssiModel.name isEqualToString:@"BLERL"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERL")]) {
                        rssiModel.name = @"BLERL";
                        [tempArray addObject:rssiModel];
                    } else if ([rssiModel.name isEqualToString:@"BLERR"] || [rssiModel.name isEqualToString:getBleOtaEcuNameMap(@"BLERR")]) {
                        rssiModel.name = @"BLERR";
                        [tempArray addObject:rssiModel];
                    }
                }
            }
            if (tempArray.count > 0) {
                [tempTotalArray addObject:tempArray];
            }
        }
        if (tempTotalArray.count >= selfCalibrationV2.count) {
            return [selfCalibrationV2 copy];
        } else {
            return nil;
        }
    }
}

- (NSArray *)covertOldV3DataToNew:(NSArray *)txPowerArray {
    if (![txPowerArray isKindOfClass:[NSArray class]]) {
        return nil;
    }
    if (txPowerArray.count == 0) {
        return nil;
    }
    NSString *first = txPowerArray.firstObject;
    if (![first isKindOfClass:[NSString class]]) {
        return nil;
    }
    NSMutableArray *tempArray = [NSMutableArray array];
    for (NSString *selfCalibrationStr in txPowerArray) {
        NSCharacterSet *hexSet = [NSCharacterSet characterSetWithCharactersInString:@"0123456789abcdefABCDEF"];
        NSCharacterSet *inStringSet = [NSCharacterSet characterSetWithCharactersInString:selfCalibrationStr];
        if ([hexSet isSupersetOfSet:inStringSet]) {
            [tempArray addObject:selfCalibrationStr];
        } else {
            NSData *data = [selfCalibrationStr dataUsingEncoding:NSISOLatin1StringEncoding];
            [tempArray addObject:[data hexString]];
        }
    }
    return [tempArray copy];
}

