        [kv setObject:dynamicConfig forKey:kOcmDynamicConfig];
        [kv sync];
    } else {
        MMKV *kv = [self getUserInfoMMKV:[self getUserInfoDict]];
        [kv removeValueForKey:kOcmDynamicConfig];
        [kv sync];
    }
    float unlockDistance = [self getUnlockDistance];
    float lockDistance = [self getLockDistance];
    float startDistacne = [self getStartDistance];
    float enableDistance = [self getEnableUnlockDistance];
    float lockHoldOnSecond = [self getLockHoldOnSecond];
    float parkingEnableDistance = [self getParkingEnableDistance];
    [self sdk_syncUnlockDistance: unlockDistance];
    [self sdk_syncLockDistance: lockDistance];
    [self sdk_syncStartDistance: startDistacne];
    [self sdk_syncEnableUnlockDistance: enableDistance];
    [self sdk_syncLockHoldOnSecond: lockHoldOnSecond];
    [self sdk_syncParkingEnableDistance: parkingEnableDistance];
}

