#pragma mark setter && getter
- (void)setLocalModel:(XPKeySettingDataV2Model *)localModel {
    _localModel = localModel;
    [self.keySettingDispose dispose];
    if (localModel) {
        RACCompoundDisposable *dispose = [RACCompoundDisposable compoundDisposable];
        @weakify(self)
        [dispose addDisposable:[RACObserve(self.localModel, unlockLogin).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            NSInteger unlockLogin = [x intValue];
            [self sdk_syncUnlockLogin: (BOOL)unlockLogin];
        }]];

        [dispose addDisposable:[RACObserve(self.localModel, welcomeMode).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            NSInteger welcomeMode = [x intValue];
            [self sdk_syncPollingUnlockIsWelocme: (BOOL)welcomeMode];
        }]];

        [dispose addDisposable:[[RACSignal merge:@[RACObserve(self.localModel, enablePE).distinctUntilChanged, RACObserve(self.localModel, walletKeyPe).distinctUntilChanged]] subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            NSInteger  pollingEnableSwitch = [x intValue];
            [self sdk_syncPollingEnableSwitch:pollingEnableSwitch];
        }]];

        [dispose addDisposable:[[RACSignal merge:@[RACObserve(self.localModel, pollingUnlock).distinctUntilChanged, RACObserve(self.localModel, pollingLock).distinctUntilChanged]] subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            [self sdk_syncPollingRunMode];
        }]];

        [dispose addDisposable:[[RACSignal merge:@[RACObserve(self.localModel, walletKeyAutoUnlock).distinctUntilChanged, RACObserve(self.localModel, walletKeyAutoLock).distinctUntilChanged]] subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            [self sdk_syncWalletPollingRunMode];
        }]];

        [dispose addDisposable:[RACObserve(self.localModel, userUnlockDistance).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            float unlockDistance = [x floatValue];
            float lockDistance = [self getLockDistance];
            [self sdk_syncUnlockDistance: unlockDistance];
            [self sdk_syncLockDistance: lockDistance];
        }]];


        [dispose addDisposable:[RACObserve(self.localModel, selfCalibrationV3).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            [self sdk_syncSelfCalibrationTxPowerArrayV3: self.localModel.selfCalibrationV3];
        }]];

        [dispose addDisposable:[RACObserve(self.localModel, isDriverMode).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            [self sdk_syncDriverMode:[x boolValue]];
        }]];

        [dispose addDisposable:[RACObserve(self.localModel, selfCalibrationV2).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            @strongify(self)
            [self sdk_syncSelfCalibrationTxPowerArrayV2: self.localModel.selfCalibrationV2];
        }]];

        [dispose addDisposable:[RACObserve(self.localModel, lockSound).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            NSInteger lockSound = [x integerValue];
            @strongify(self)
            [self sdk_syncLockWithSound: (BOOL)lockSound];
        }]];

        [dispose addDisposable:[RACObserve(self.localModel, sensitivity).distinctUntilChanged subscribeNext:^(id  _Nullable x) {
            bool sensitivity = [x boolValue];
            @strongify(self)
            [self sdk_syncBleAutoSensitivity: sensitivity];
        }]];

        self.keySettingDispose = dispose;
    }
}


